def _iso_now() -> str:
    return utc_now().isoformat()


def _to_iso(dt: datetime) -> str:
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=UTC)
    return dt.astimezone(UTC).isoformat()


def _parse_iso(value: str) -> datetime:
    parsed = datetime.fromisoformat(str(value).replace("Z", "+00:00"))
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=UTC)
    return parsed.astimezone(UTC)


def _coerce_iso_datetime(value: str | None) -> datetime | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    try:
        return _parse_iso(raw)
    except Exception:
        return None


def _sqlite_low_space_error(exc: BaseException) -> bool:
    message = str(exc).lower()
    return "database or disk is full" in message or "disk i/o error" in message


def _setup_is_tight_spread_family_name(setup: str) -> bool:
    text = str(setup or "").upper()
    if not text:
        return False
    return any(
        token in text
        for token in (
            "SCALP",
            "MOMENTUM",
            "PULLBACK",
            "REVERSAL",
            "SWEEP",
            "BREAKOUT",
            "CONTINUATION",
            "MICRO",
        )
    )


def _setup_is_scalp_delivery_family_name(setup: str, *, setup_type: str = "", symbol_key: str = "") -> bool:
    setup_text = str(setup or "").upper()
    setup_type_text = str(setup_type or "").upper()
    normalized_symbol = str(symbol_key or "").upper()
    if not setup_text and not setup_type_text:
        return False
    if "GRID" in setup_text or setup_type_text in {"SCALP", "GRID", "GRID_MANAGE"}:
        return True
    if any(token in setup_text for token in ("SCALP", "MICRO", "SPRAY", "QUICK")):
        return True
    if normalized_symbol == "XAUUSD" and any(token in setup_text for token in ("ATR_EXPANSION_SCALPER", "GRID_START", "GRID_ADD", "M5_GRID")):
        return True
    if normalized_symbol in {"BTCUSD", "NAS100", "USDJPY"} and any(token in setup_text for token in ("SCALP", "MICRO")):
        return True
    return False


def _scalp_delivery_entry_guard_reason(
    *,
    setup: str,
    setup_type: str,
    symbol_key: str,
    side: str,
    reference_entry_price: float,
    live_entry_price: float,
    stop_price: float,
    tp_price: float,
    spread_points: float,
    typical_spread_points: float,
    point_size: float,
    reanchor_drift_stop_ratio: float,
    block_drift_stop_ratio: float,
    reanchor_spread_mult: float,
    block_spread_mult: float,
    spread_to_target_ratio_cap: float,
) -> tuple[str | None, dict[str, float]]:
    if not _setup_is_scalp_delivery_family_name(setup, setup_type=setup_type, symbol_key=symbol_key):
        return None, {}
    setup_text = str(setup or "").upper()
    setup_type_text = str(setup_type or "").upper()
    is_grid_family = "GRID" in setup_text or setup_type_text in {"GRID", "GRID_MANAGE"}
    point_value = max(float(point_size), 1e-9)
    reference_entry = max(0.0, float(reference_entry_price))
    live_entry = max(0.0, float(live_entry_price))
    spread_value = max(0.0, float(spread_points))
    typical_spread = max(1.0, float(typical_spread_points))
    stop_distance_points = abs(float(live_entry or reference_entry) - float(stop_price)) / point_value if float(stop_price) > 0.0 else 0.0
    tp_distance_points = abs(float(tp_price) - float(live_entry or reference_entry)) / point_value if float(tp_price) > 0.0 else 0.0
    entry_reference_gap_ratio = (
        abs(float(live_entry) - float(reference_entry)) / max(abs(float(live_entry)), abs(float(reference_entry)), 1.0)
        if reference_entry > 0.0 and live_entry > 0.0
        else 0.0
    )
    if str(side or "").upper() == "BUY":
        adverse_entry_price = max(0.0, live_entry - reference_entry)
    else:
        adverse_entry_price = max(0.0, reference_entry - live_entry)
    adverse_entry_drift_points = adverse_entry_price / point_value
    reanchor_threshold_points = max(
        1.0,
        stop_distance_points * max(0.0, float(reanchor_drift_stop_ratio)),
    )
    block_threshold_points = max(
        reanchor_threshold_points * 1.30,
        typical_spread * max(0.0, float(block_spread_mult)),
        stop_distance_points * max(0.0, float(block_drift_stop_ratio)),
    )
    spread_to_target_ratio = spread_value / max(tp_distance_points, 1.0) if tp_distance_points > 0.0 else 0.0
    details = {
        "adverse_entry_drift_points": float(adverse_entry_drift_points),
        "adverse_entry_drift_price": float(adverse_entry_price),
        "reanchor_threshold_points": float(reanchor_threshold_points),
        "block_threshold_points": float(block_threshold_points),
        "spread_to_target_ratio": float(spread_to_target_ratio),
        "spread_to_target_ratio_cap": float(spread_to_target_ratio_cap),
        "spread_points_live": float(spread_value),
        "typical_spread_points": float(typical_spread),
        "stop_distance_points_live": float(stop_distance_points),
        "tp_distance_points_live": float(tp_distance_points),
        "entry_reference_gap_ratio": float(entry_reference_gap_ratio),
    }
    stale_reference_reanchor = (
        not is_grid_family
        and reference_entry > 0.0
        and live_entry > 0.0
        and stop_distance_points > 0.0
        and entry_reference_gap_ratio >= 0.12
    )
    spread_eats_target = (
        tp_distance_points > 0.0
        and spread_to_target_ratio > max(0.0, float(spread_to_target_ratio_cap))
        and spread_value >= typical_spread * 1.10
    )
    if adverse_entry_drift_points >= block_threshold_points:
        if stale_reference_reanchor:
            return "scalp_entry_reanchor", details
        return "scalp_entry_drift_too_high", details
    if is_grid_family and spread_eats_target:
        return "scalp_spread_eats_target", details
    if adverse_entry_drift_points >= reanchor_threshold_points:
        return "scalp_entry_reanchor", details
    if spread_eats_target:
        return "scalp_spread_eats_target", details
    return None, details


def _spread_to_stop_guard_reason(
    *,
    setup: str,
    spread_points: float,
    entry_price: float,
    stop_price: float,
    point_size: float,
    is_grid: bool,
    max_ratio_grid: float,
    max_ratio_other: float,
    max_ratio_scalp: float,
    min_trigger_points: float,
) -> tuple[str | None, dict[str, float]]:
    spread_value = max(0.0, float(spread_points))
    point_value = max(float(point_size), 1e-9)
    stop_distance_points = abs(float(entry_price) - float(stop_price)) / point_value
    details = {
        "spread_to_stop_ratio": 0.0,
        "stop_distance_points": float(stop_distance_points),
        "spread_to_stop_ratio_cap": 0.0,
    }
    if spread_value <= 0.0 or stop_distance_points <= 0.0:
        return None, details
    ratio = spread_value / max(stop_distance_points, 1.0)
    if bool(is_grid):
        ratio_cap = float(max_ratio_grid)
    else:
        ratio_cap = float(max_ratio_other)
        if _setup_is_tight_spread_family_name(setup):
            ratio_cap = min(ratio_cap, float(max_ratio_scalp))
    details["spread_to_stop_ratio"] = float(ratio)
    details["spread_to_stop_ratio_cap"] = float(ratio_cap)
    if spread_value < max(float(min_trigger_points), 0.0):
        return None, details
    if ratio > ratio_cap:
        return ("grid_spread_disorder_stop_relative" if bool(is_grid) else "spread_disorder_stop_relative"), details
    return None, details


def _spread_spike_guard_reason(
    *,
    session_name: str,
    spread_points: float,
    spread_reference_points: float,
    spread_atr_points: float,
    is_grid: bool,
    atr_guard_multiplier: float,
    prime_session_ratio_cap: float,
    asia_session_ratio_cap: float,
    default_session_ratio_cap: float,
    auto_reduce_ratio: float,
    auto_reduce_lot_multiplier: float,
    auto_skip_ratio: float,
) -> tuple[str | None, dict[str, float]]:
    spread_value = max(0.0, float(spread_points))
    spread_reference = max(1.0, float(spread_reference_points))
    spread_atr = max(0.0, float(spread_atr_points))
    session_key = str(session_name or "").upper()
    if session_key in {"LONDON", "OVERLAP", "NEW_YORK"}:
        session_ratio_cap = float(prime_session_ratio_cap)
    elif session_key in {"TOKYO", "SYDNEY", "ASIA"}:
        session_ratio_cap = float(asia_session_ratio_cap)
    else:
        session_ratio_cap = float(default_session_ratio_cap)
    spread_ratio = spread_value / max(spread_reference, 1.0)
    atr_guard_points = spread_reference + (max(0.0, float(atr_guard_multiplier)) * spread_atr)
    session_guard_points = spread_reference * max(1.0, session_ratio_cap)
    allowed_spread_points = max(session_guard_points, atr_guard_points)
    details = {
        "spread_reference_points": float(spread_reference),
        "spread_atr_points": float(spread_atr),
        "spread_ratio_live": float(spread_ratio),
        "spread_session_ratio_cap": float(session_ratio_cap),
        "spread_atr_guard_points": float(atr_guard_points),
        "spread_session_guard_points": float(session_guard_points),
        "spread_allowed_points": float(allowed_spread_points),
        "spread_lot_multiplier": 1.0,
    }
    if spread_value <= 0.0:
        return None, details
    if spread_ratio > max(1.0, float(auto_skip_ratio)):
        return ("grid_spread_spike_extreme_skip" if bool(is_grid) else "spread_spike_extreme_skip"), details
    if spread_ratio > max(1.0, float(auto_reduce_ratio)):
        details["spread_lot_multiplier"] = clamp(float(auto_reduce_lot_multiplier), 0.1, 1.0)
    if spread_value > allowed_spread_points:
        reason = "spread_spike_session_ratio"
        if atr_guard_points > session_guard_points:
            reason = "spread_spike_atr"
        if bool(is_grid):
            reason = f"grid_{reason}"
        return reason, details
    return None, details


def _append_jsonl(path_value: str | Path, payload: dict[str, Any]) -> None:
    path = Path(path_value)
    ensure_parent(path)
    with path.open("a", encoding="utf-8") as handle:
        handle.write(json.dumps(payload, sort_keys=True) + "\n")


def _write_json(path_value: str | Path, payload: dict[str, Any]) -> None:
    path = Path(path_value)
    ensure_parent(path)
    path.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")


