def runtime_entry_block_state(now_ts: datetime | None = None) -> dict[str, Any]:
    now_value = now_ts or utc_now()
    control_state = _SHARED_OPERATOR_CONTROL_STATE if isinstance(_SHARED_OPERATOR_CONTROL_STATE, dict) else {}
    startup_state = _SHARED_STARTUP_RUNTIME_STATE if isinstance(_SHARED_STARTUP_RUNTIME_STATE, dict) else {}
    if bool(control_state.get("kill_switch")):
        return {
            "blocked": True,
            "reason": "operator_kill_switch",
            "pause_trading": bool(control_state.get("pause_trading")),
            "kill_switch": True,
            "entries_blocked_until": str(startup_state.get("entries_blocked_until") or ""),
        }
    if bool(control_state.get("pause_trading")):
        return {
            "blocked": True,
            "reason": "operator_pause_trading",
            "pause_trading": True,
            "kill_switch": bool(control_state.get("kill_switch")),
            "entries_blocked_until": str(startup_state.get("entries_blocked_until") or ""),
        }
    block_until_raw = str(startup_state.get("entries_blocked_until") or "").strip()
    if block_until_raw:
        try:
            block_until = _parse_iso(block_until_raw)
            if block_until > now_value:
                return {
                    "blocked": True,
                    "reason": "startup_warmup",
                    "pause_trading": bool(control_state.get("pause_trading")),
                    "kill_switch": bool(control_state.get("kill_switch")),
                    "entries_blocked_until": block_until_raw,
                }
        except Exception:
            pass
    return {
        "blocked": False,
        "reason": "",
        "pause_trading": bool(control_state.get("pause_trading")),
        "kill_switch": bool(control_state.get("kill_switch")),
        "entries_blocked_until": str(startup_state.get("entries_blocked_until") or ""),
    }


def _counts_toward_stale_family_archive(reason: str) -> bool:
    normalized = str(reason or "").strip().lower()
    if not normalized:
        return True
    transient_exact = {
        "stale_idea_family_archived",
        "idea_cooldown_active",
        "idea_recheck_wait",
        "duplicate_or_active_signal",
        "open_lock_active",
        "queue_rejected",
        "delivery_lock_timeout",
        "candidate_pending_watchdog_escalated",
        "cadence_wait",
    }
    transient_prefixes = (
        "news_",
        "blocked_",
        "market_closed",
        "weekend_closed",
        "session_",
        "outside_configured_session",
        "omega_",
        "soft_dd_",
        "hard_dd_",
        "daily_",
        "max_trades_per_",
        "global_cooldown",
        "delivery_budget_",
    )
    if normalized in transient_exact:
        return False
    return not any(normalized.startswith(prefix) for prefix in transient_prefixes)


def _queue_row_delivery_protected(row: sqlite3.Row | dict[str, Any], *, now_ts: datetime, fair_ttl_seconds: int) -> bool:
    status = str((row["status"] if isinstance(row, sqlite3.Row) else row.get("status")) or "").upper()
    if status == "DELIVERED":
        lease_until_raw = row["lease_until_utc"] if isinstance(row, sqlite3.Row) else row.get("lease_until_utc")
        if lease_until_raw:
            try:
                return _parse_iso(str(lease_until_raw)) > now_ts.astimezone(UTC)
            except Exception:
                return False
        return False
    if status != "QUEUED":
        return False
    anchor_raw = (
        row["updated_at"] if isinstance(row, sqlite3.Row) else row.get("updated_at")
    ) or (
        row["created_at"] if isinstance(row, sqlite3.Row) else row.get("created_at")
    )
    if not anchor_raw:
        return False
    try:
        anchor = _parse_iso(str(anchor_raw))
    except Exception:
        return False
    age_seconds = max(0.0, (now_ts.astimezone(UTC) - anchor).total_seconds())
    return age_seconds <= max(5, int(fair_ttl_seconds))


def _normalize_symbol_key(value: str) -> str:
    normalized = "".join(char for char in str(value).upper() if char.isalnum())
    if normalized.startswith("XAUUSD") or normalized.startswith("GOLD"):
        return "XAUUSD"
    if normalized.startswith("XAGUSD") or normalized.startswith("SILVER"):
        return "XAGUSD"
    if normalized.startswith("BTCUSD") or normalized.startswith("BTCUSDT") or normalized.startswith("XBTUSD"):
        return "BTCUSD"
    if normalized.startswith(("DOGUSD", "DOGEUSD", "DOGE")):
        return "DOGUSD"
    if normalized.startswith(("TRUMPUSD", "TRUMPUSDT", "TRUMP")):
        return "TRUMPUSD"
    if normalized.startswith(("NAS100", "US100", "NASDAQ", "USTEC", "NAS", "NQ")):
        return "NAS100"
    if normalized.startswith(("USOIL", "XTIUSD", "OILUSD", "WTI", "CL", "OIL", "USO")):
        return "USOIL"
    if normalized.startswith("EURUSD"):
        return "EURUSD"
    if normalized.startswith("GBPUSD"):
        return "GBPUSD"
    if normalized.startswith("USDJPY"):
        return "USDJPY"
    if normalized.startswith("AUDJPY"):
        return "AUDJPY"
    if normalized.startswith("NZDJPY"):
        return "NZDJPY"
    if normalized.startswith("AUDNZD"):
        return "AUDNZD"
    if normalized.startswith("EURJPY"):
        return "EURJPY"
    if normalized.startswith("GBPJPY"):
        return "GBPJPY"
    if normalized.startswith("AAPL"):
        return "AAPL"
    if normalized.startswith(("NVIDIA", "NVDA")):
        return "NVIDIA"
    return normalized


def _session_name_utc(current: datetime) -> str:
    dynamic = dominant_session_name(current)
    return dynamic if dynamic != "OFF" else "SYDNEY"


def _safe_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(value)
    except (TypeError, ValueError):
        return float(default)


def _safe_int(value: Any, default: int = 0) -> int:
    try:
        return int(value)
    except (TypeError, ValueError):
        return int(default)


def _bridge_account_scaling_summary(
    *,
    active_runtime: Mapping[str, Any],
    active_snapshot: Mapping[str, Any] | None,
    rollout_stats: Mapping[str, Any],
) -> dict[str, Any]:
    snapshot = dict(active_snapshot or {})
    runtime = dict(active_runtime or {})
    balance = _safe_float(runtime.get("live_balance", snapshot.get("balance")), 0.0)
    equity = _safe_float(runtime.get("live_equity", snapshot.get("equity")), balance)
    free_margin = _safe_float(runtime.get("live_free_margin", snapshot.get("free_margin")), equity)
    overall = dict(rollout_stats.get("overall") or {}) if isinstance(rollout_stats, Mapping) else {}
    trades = _safe_int(rollout_stats.get("trade_count", overall.get("trades")), 0) if isinstance(rollout_stats, Mapping) else 0
    win_rate = _safe_float(overall.get("win_rate"), 0.0)
    expectancy = _safe_float(overall.get("expectancy_r"), 0.0)

    phase = "PHASE_1"
    reason = "equity_below_growth_threshold"
    risk_pct = 0.01
    max_risk_pct = 0.01
    daily_trade_cap = 240
    overflow_daily_trade_cap = 720
    ai_mode = "moderate"
    next_requirements: dict[str, Any] = {
        "phase": "PHASE_2",
        "min_equity": 100.0,
        "min_trades": 12,
        "min_win_rate": 0.50,
        "min_expectancy_r": 0.05,
    }
    if equity >= 1_500.0 and trades >= 60 and win_rate >= 0.56 and expectancy >= 0.10:
        phase = "PHASE_4"
        reason = "small_account_scaling_confirmed"
        risk_pct = 0.02
        max_risk_pct = 0.025
        daily_trade_cap = 360
        overflow_daily_trade_cap = 960
        ai_mode = "aggressive"
        next_requirements = {"phase": "PHASE_5", "min_equity": 5_000.0, "min_trades": 120, "min_win_rate": 0.57, "min_expectancy_r": 0.12}
    elif equity >= 300.0 and trades >= 30 and win_rate >= 0.55 and expectancy >= 0.10:
        phase = "PHASE_3"
        reason = "equity_and_performance_confirmed"
        risk_pct = 0.02 if equity >= 500.0 else 0.015
        max_risk_pct = 0.025
        daily_trade_cap = 320
        overflow_daily_trade_cap = 900
        ai_mode = "aggressive"
        next_requirements = {"phase": "PHASE_4", "min_equity": 1_500.0, "min_trades": 60, "min_win_rate": 0.56, "min_expectancy_r": 0.10}
    elif equity >= 100.0 and trades >= 12 and win_rate >= 0.50 and expectancy >= 0.05:
        phase = "PHASE_2"
        reason = "edge_emerging"
        risk_pct = 0.01
        max_risk_pct = 0.025
        daily_trade_cap = 280
        overflow_daily_trade_cap = 760
        ai_mode = "moderate"
        next_requirements = {"phase": "PHASE_3", "min_equity": 300.0, "min_trades": 30, "min_win_rate": 0.55, "min_expectancy_r": 0.10}
    elif equity >= 100.0:
        reason = "equity_up_but_performance_unproven"

    fallback = {
        "balance": balance,
        "equity": equity,
        "free_margin": free_margin,
        "account_increase_detected": runtime.get("account_increase_detected"),
        "account_decrease_detected": runtime.get("account_decrease_detected"),
        "material_account_change_detected": runtime.get("material_account_change_detected"),
        "sizing_updated": runtime.get("sizing_updated") if runtime.get("sizing_updated") is not None else bool(equity > 0.0),
        "sizing_updated_at": runtime.get("sizing_updated_at") or snapshot.get("updated_at") or _iso_now(),
        "equity_band": runtime.get("equity_band") or ("bootstrap_balanced" if equity < 160.0 else "growth_ready"),
        "high_watermark_equity": runtime.get("high_watermark_equity") or equity,
        "balance_change_pct": runtime.get("balance_change_pct"),
        "equity_change_pct": runtime.get("equity_change_pct"),
        "amount_increase": runtime.get("amount_increase"),
        "prior_risk_budget": runtime.get("prior_risk_budget"),
        "new_risk_budget": runtime.get("new_risk_budget") or round(equity * risk_pct, 2),
        "sizing_updated_reason": runtime.get("sizing_updated_reason") or "bridge_account_snapshot_fallback",
        "current_phase": phase,
        "phase_reason": reason,
        "equity_phase_thresholds": {
            "PHASE_1_max": 99.99,
            "PHASE_2_min": 100.0,
            "PHASE_3_min": 300.0,
            "PHASE_4_min": 1500.0,
            "PHASE_5_min": 5000.0,
        },
        "performance_phase_thresholds": {
            "PHASE_2": {"min_trades": 12, "min_win_rate": 0.50, "min_expectancy_r": 0.05},
            "PHASE_3": {"min_trades": 30, "min_win_rate": 0.55, "min_expectancy_r": 0.10},
            "PHASE_4": {"min_trades": 60, "min_win_rate": 0.56, "min_expectancy_r": 0.10},
        },
        "next_phase_requirements": next_requirements,
        "current_daily_trade_cap": daily_trade_cap,
        "current_overflow_daily_trade_cap": overflow_daily_trade_cap,
        "current_risk_pct": risk_pct,
        "current_max_risk_pct": max_risk_pct,
        "current_ai_threshold_mode": ai_mode,
    }
    for key in ("current_phase", "phase_reason", "current_daily_trade_cap", "current_overflow_daily_trade_cap", "current_risk_pct", "current_max_risk_pct", "current_ai_threshold_mode"):
        if runtime.get(key) not in (None, ""):
            fallback[key] = runtime.get(key)
    for key in ("equity_phase_thresholds", "performance_phase_thresholds", "next_phase_requirements"):
        if isinstance(runtime.get(key), Mapping) and runtime.get(key):
            fallback[key] = dict(runtime.get(key) or {})
    return fallback


def _blocker_entry(
    *,
    reason: str,
    set_at: str = "",
    expires_at: str = "",
    sydney_reset: bool = False,
    hard_blocker: bool = False,
    details: dict[str, Any] | None = None,
) -> dict[str, Any]:
    return {
        "reason": str(reason or ""),
        "set_at": str(set_at or ""),
        "expires_at": str(expires_at or ""),
        "sydney_reset": bool(sydney_reset),
        "hard_blocker": bool(hard_blocker),
        "details": dict(details or {}),
    }


def _runtime_active_blockers(
    *,
    symbol_key: str,
    runtime: dict[str, Any],
    now_ts: datetime,
    symbol_state: dict[str, Any] | None = None,
    entry_block_state: dict[str, Any] | None = None,
    market_open_status: str = "",
) -> list[dict[str, Any]]:
    blockers: list[dict[str, Any]] = []
    state = dict(symbol_state or {})
    control_block = dict(entry_block_state or {})
    market_status = str(market_open_status or "").upper()
    if market_status and market_status not in {"OPEN", "OPEN_24_7", "PRE_OPEN"}:
        blockers.append(
            _blocker_entry(
                reason=market_status.lower(),
                hard_blocker=True,
                sydney_reset=False,
            )
        )
    if bool(control_block.get("blocked")):
        blockers.append(
            _blocker_entry(
                reason=str(control_block.get("reason") or "entry_blocked"),
                expires_at=str(control_block.get("entries_blocked_until") or ""),
                hard_blocker=bool(control_block.get("kill_switch") or control_block.get("pause_trading")),
                sydney_reset=False,
            )
        )
    temporary_pause_reason = str(runtime.get("temporary_pause_reason") or "").strip()
    temporary_pause_set_at = str(runtime.get("temporary_pause_set_at") or runtime.get("updated_at") or "")
    temporary_pause_until = str(runtime.get("temporary_pause_until") or runtime.get("performance_cooldown_until") or "")
    if temporary_pause_reason:
        blockers.append(
            _blocker_entry(
                reason=temporary_pause_reason,
                set_at=temporary_pause_set_at,
                expires_at=temporary_pause_until,
                sydney_reset=True,
                hard_blocker=False,
            )
        )
    elif bool(runtime.get("performance_cooldown_active")) and temporary_pause_until:
        blockers.append(
            _blocker_entry(
                reason="performance_cooldown",
                set_at=temporary_pause_set_at,
                expires_at=temporary_pause_until,
                sydney_reset=True,
                hard_blocker=False,
            )
        )
    strategy_cooldown_until = str(runtime.get("strategy_cooldown_until") or state.get("strategy_cooldown_until") or "")
    if strategy_cooldown_until:
        try:
            if _parse_iso(strategy_cooldown_until) > now_ts.astimezone(UTC):
                blockers.append(
                    _blocker_entry(
                        reason="pair_strategy_loss_cooldown",
                        expires_at=strategy_cooldown_until,
                        sydney_reset=True,
                    )
                )
        except Exception:
            pass
    cooldown_until = str(runtime.get("cooldown_until") or state.get("cooldown_until") or "")
    if cooldown_until:
        try:
            if _parse_iso(cooldown_until) > now_ts.astimezone(UTC):
                blockers.append(
                    _blocker_entry(
                        reason=str(runtime.get("cooldown_state") or state.get("last_block_reason") or "symbol_cooldown"),
                        expires_at=str(cooldown_until),
                        sydney_reset=True,
                    )
                )
        except Exception:
            pass
    last_reject_reason = str(runtime.get("last_reject_reason") or "")
    if last_reject_reason.startswith("delivery_cooldown_"):
        remaining = _safe_int(last_reject_reason.rsplit("_", 1)[-1].rstrip("s"), 0)
        expires_at = ""
        if remaining > 0:
            expires_at = _to_iso(now_ts + timedelta(seconds=remaining))
        blockers.append(
            _blocker_entry(
                reason=last_reject_reason,
                expires_at=expires_at,
                sydney_reset=False,
            )
        )
    unique: list[dict[str, Any]] = []
    seen: set[tuple[str, str]] = set()
    for blocker in blockers:
        key = (str(blocker.get("reason") or ""), str(blocker.get("expires_at") or ""))
        if key in seen:
            continue
        seen.add(key)
        unique.append(blocker)
    return unique


def _runtime_management_stats(symbol_key: str, runtime: dict[str, Any]) -> dict[str, Any]:
    counts = dict(runtime.get("management_action_counts") or {})
    trail_updates = _safe_int(counts.get("TRAIL_STOP"), 0)
    tighten_updates = _safe_int(counts.get("TIGHTEN_STOP"), 0)
    partials = _safe_int(counts.get("PARTIAL_EXIT"), 0)
    tp_extensions = _safe_int(counts.get("EXTEND_TP"), 0)
    exits = _safe_int(counts.get("FULL_EXIT"), 0) + _safe_int(counts.get("CLOSE_POSITION"), 0)
    return {
        "symbol": str(symbol_key or "").upper(),
        "actions_total": int(sum(max(0, _safe_int(value, 0)) for value in counts.values())),
        "trail_updates": int(trail_updates),
        "be_moves": int(tighten_updates),
        "partials": int(partials),
        "tp_extensions": int(tp_extensions),
        "swing_conversions": int(_safe_int(runtime.get("management_swing_conversion_count"), 0)),
        "reentry_signals": int(_safe_int(runtime.get("management_reentry_signal_count"), 0)),
        "last_action": str(runtime.get("last_management_action") or ""),
        "last_reason": str(runtime.get("last_management_reason") or ""),
        "last_action_at": str(runtime.get("last_management_action_at") or ""),
        "generation_allowed": bool(runtime.get("management_generation_allowed")),
        "runner_mode_active": bool(str(runtime.get("trade_state") or "").upper() in {"RUNNER", "SWING"}),
        "active_exit_bias": "aggressive" if symbol_key in {"XAUUSD", "BTCUSD"} else "adaptive",
        "scratch_exits": int(_safe_int(runtime.get("management_scratch_exit_count"), 0)) + exits,
        "cadence_seconds": int(_safe_int(runtime.get("last_management_cadence_seconds"), 0)),
        "next_review_after": str(runtime.get("management_next_review_after") or ""),
        "cadence_waits": int(_safe_int(runtime.get("management_cadence_wait_count"), 0)),
        "current_capture_gap_r": float(_safe_float(runtime.get("recent_opportunity_capture_gap_r"), 0.0)),
        "current_management_quality_score": float(_safe_float(runtime.get("recent_management_quality_score"), 0.0)),
        "last_review_at": str(runtime.get("last_management_review_at") or ""),
        "last_review_action": str(runtime.get("last_management_review_action") or ""),
        "last_review_reason": str(runtime.get("last_management_review_reason") or ""),
        "last_hold_reason": str(runtime.get("last_management_hold_reason") or ""),
        "last_trail_update_at": str(runtime.get("last_trail_update_at") or ""),
        "last_tp_extension_at": str(runtime.get("last_tp_extension_at") or ""),
        "last_partial_exit_at": str(runtime.get("last_partial_exit_at") or ""),
        "last_intervention_at": str(runtime.get("last_management_intervention_at") or ""),
        "watchdog_triggers": int(_safe_int(runtime.get("management_watchdog_trigger_count"), 0)),
        "last_watchdog_at": str(runtime.get("last_management_watchdog_at") or ""),
        "last_watchdog_reason": str(runtime.get("last_management_watchdog_reason") or ""),
    }


def _runtime_xau_btc_trajectory_stats(symbol_key: str, runtime: dict[str, Any], *, session_name: str) -> dict[str, Any]:
    normalized_symbol = _normalize_symbol_key(symbol_key)
    if normalized_symbol not in {"XAUUSD", "BTCUSD"}:
        return {}
    delivered_15m = max(0, _safe_int(runtime.get("delivered_actions_last_15m"), 0))
    candidate_attempts_15m = max(0, _safe_int(runtime.get("candidate_attempts_last_15m"), 0))
    delivered_10m = int(round(delivered_15m * (10.0 / 15.0)))
    candidate_attempts_10m = int(round(candidate_attempts_15m * (10.0 / 15.0)))
    session_key = str(session_name or "").upper()
    if normalized_symbol == "XAUUSD" and session_key in {"LONDON", "OVERLAP", "NEW_YORK"}:
        soft_target_low, soft_target_high = 6, 8
    elif normalized_symbol == "BTCUSD":
        soft_target_low, soft_target_high = (3, 5) if session_key in {"SYDNEY", "TOKYO"} else (4, 6)
    else:
        soft_target_low, soft_target_high = 2, 4
    lag_units = max(0, soft_target_low - delivered_10m)
    return {
        "symbol": normalized_symbol,
        "session": session_key,
        "soft_target_trades_last_10m": {"low": int(soft_target_low), "high": int(soft_target_high)},
        "soft_target_trades_last_1h": {"low": int(soft_target_low * 6), "high": int(soft_target_high * 6)},
        "actual_trades_last_10m": int(delivered_10m),
        "actual_candidates_last_10m": int(candidate_attempts_10m),
        "actual_trades_last_15m": int(delivered_15m),
        "lagging": bool(delivered_10m < soft_target_low),
        "lag_units": int(lag_units),
        "catchup_pressure": float(clamp((lag_units / max(soft_target_high, 1)) * 0.6, 0.0, 0.6)),
    }


def _runtime_no_trade_scoreboard(
    *,
    symbol_key: str,
    runtime: dict[str, Any],
    blockers: list[dict[str, Any]],
    market_open_status: str,
    session_name: str,
) -> dict[str, Any]:
    candidate_attempts = max(0, _safe_int(runtime.get("candidate_attempts_last_15m", runtime.get("candidate_count_last_15m")), 0))
    delivered_actions = max(0, _safe_int(runtime.get("delivered_actions_last_15m"), 0))
    reason_top = str(runtime.get("reason_top_last_15m") or runtime.get("last_reject_reason") or "").strip()
    top_blockers = [str(item.get("reason") or "") for item in blockers[:3] if str(item.get("reason") or "").strip()]
    scarcity_state = "flowing"
    if str(market_open_status or "").upper() not in {"OPEN", "OPEN_24_7", "PRE_OPEN"}:
        scarcity_state = "market_closed"
    elif delivered_actions <= 0 and candidate_attempts <= 0:
        scarcity_state = "no_candidates"
    elif delivered_actions <= 0 and top_blockers:
        scarcity_state = "blocked_after_scan"
    elif delivered_actions <= 0:
        scarcity_state = "candidate_not_executed"
    return {
        "symbol": str(symbol_key or "").upper(),
        "session": str(session_name or "").upper(),
        "scarcity_state": scarcity_state,
        "candidate_attempts_last_15m": int(candidate_attempts),
        "delivered_actions_last_15m": int(delivered_actions),
        "top_reason_last_15m": reason_top,
        "top_blockers": top_blockers,
        "undertrading": bool(delivered_actions <= 0 and candidate_attempts < 2),
    }


def _self_heal_status_summary(maintenance_runtime_state: dict[str, Any]) -> dict[str, Any]:
    last_actions = list(maintenance_runtime_state.get("last_self_heal_actions") or [])
    latest_action = dict(last_actions[0]) if last_actions else {}
    return {
        "last_self_heal_action": latest_action,
        "last_self_heal_actions": last_actions[:5],
        "last_4h_retrain_at": str(maintenance_runtime_state.get("last_4h_retrain_at") or ""),
        "last_4h_retrain_status": str(maintenance_runtime_state.get("last_4h_retrain_status") or ""),
        "risk_reduction_active": bool(maintenance_runtime_state.get("risk_reduction_active", False)),
        "risk_reduction_multiplier": float(maintenance_runtime_state.get("risk_reduction_multiplier", 1.0) or 1.0),
        "quota_recovery_mode": bool(maintenance_runtime_state.get("quota_recovery_mode", False)),
        "pending_sydney_block_clear": bool(maintenance_runtime_state.get("pending_sydney_block_clear", False)),
        "last_bridge_restart_requested_at": str(maintenance_runtime_state.get("last_bridge_restart_requested_at") or ""),
        "last_checkpoint_reload_requested_at": str(maintenance_runtime_state.get("last_checkpoint_reload_requested_at") or ""),
    }


def _clean_text_value(value: Any) -> str:
    text = str(value or "").strip()
    if text.lower() in {"none", "null"}:
        return ""
    return text


def _is_operator_intervention_close(reason: str) -> bool:
    normalized = str(reason or "").strip().lower()
    if not normalized:
        return False
    direct_matches = {
        "manual_close",
        "manual_exit",
        "operator_close",
        "operator_exit",
        "user_close",
        "user_exit",
    }
    if normalized in direct_matches:
        return True
    return any(token in normalized for token in ("manual", "operator", "user_close", "user_exit"))


def _json_safe(value: Any) -> Any:
    if isinstance(value, float):
        return value if math.isfinite(value) else None
    if isinstance(value, dict):
        return {str(key): _json_safe(item) for key, item in value.items()}
    if isinstance(value, list):
        return [_json_safe(item) for item in value]
    if isinstance(value, tuple):
        return [_json_safe(item) for item in value]
    return value


def _clean_snapshot_meta(payload: dict[str, Any] | None) -> dict[str, Any]:
    if not isinstance(payload, dict):
        return {}
    cleaned: dict[str, Any] = {}
    for key, value in payload.items():
        if value is None:
            continue
        if isinstance(value, str) and not value.strip():
            continue
        cleaned[str(key)] = value
    return cleaned


def _symbol_rule_with_snapshot_overrides(rule: SymbolRule, snapshot: dict[str, Any] | None) -> SymbolRule:
    snapshot_meta = _clean_snapshot_meta(snapshot)
    if not snapshot_meta:
        return rule

    def _pos_float(key: str, fallback: float) -> float:
        value = snapshot_meta.get(key)
        try:
            number = float(value)
        except (TypeError, ValueError):
            return fallback
        return number if number > 0 else fallback

    def _pos_int(key: str, fallback: int) -> int:
        value = snapshot_meta.get(key)
        try:
            number = int(float(value))
        except (TypeError, ValueError):
            return fallback
        return number if number > 0 else fallback

    return replace(
        rule,
        digits=_pos_int("digits", int(rule.digits)),
        tick_size=_pos_float("tick_size", float(rule.tick_size)),
        point=_pos_float("point", float(rule.point)),
        min_stop_points=_pos_int("stops_level", int(rule.min_stop_points)),
        freeze_points=_pos_int("freeze_level", int(rule.freeze_points)),
        typical_spread_points=_pos_float("spread_points", float(rule.typical_spread_points)),
        tick_value=_pos_float("tick_value", float(rule.tick_value)),
        contract_size=_pos_float("contract_size", float(rule.contract_size)),
    )


def _estimated_margin_per_lot(
    *,
    symbol_key: str,
    entry_price: float,
    contract_size: float,
    leverage: float,
) -> float | None:
    normalized_symbol = _normalize_symbol_key(symbol_key)
    effective_leverage = max(float(leverage or 0.0), 0.0)
    effective_contract = max(float(contract_size or 0.0), 0.0)
    effective_entry = max(float(entry_price or 0.0), 0.0)
    if effective_leverage <= 0 or effective_contract <= 0:
        return None
    if normalized_symbol in {"EURUSD", "GBPUSD", "USDJPY", "AUDJPY", "NZDJPY", "AUDNZD", "EURJPY", "GBPJPY"}:
        return effective_contract / effective_leverage
    if effective_entry <= 0:
        return None
    return (effective_entry * effective_contract) / effective_leverage


@dataclass
class BridgeServerHandle:
    thread: Thread
    server: Any
    queue: "BridgeActionQueue"

    def stop(self) -> None:
        try:
            self.server.should_exit = True
        except Exception:
            pass


