@dataclass
class BridgeActionQueue:
    db_path: Path
    ttl_seconds: int = 45
    redeliver_seconds: int = 3
    max_open_queue_per_symbol: int = 5
    open_enqueue_cooldown_seconds: int = 0
    logger: ApexLogger | None = None

    def __post_init__(self) -> None:
        ensure_parent(self.db_path)
        self._init_db()

    @staticmethod
    def _is_locked_error(exc: BaseException) -> bool:
        return "locked" in str(exc).lower()

    def _execute_write_with_retry(
        self,
        operation_name: str,
        callback: Any,
        *,
        max_attempts: int = 6,
        base_sleep_seconds: float = 0.08,
    ) -> Any:
        last_error: BaseException | None = None
        for attempt in range(1, max(1, int(max_attempts)) + 1):
            try:
                with self._connect() as connection:
                    result = callback(connection)
                    connection.commit()
                    return result
            except sqlite3.OperationalError as exc:
                last_error = exc
                if not self._is_locked_error(exc) or attempt >= max(1, int(max_attempts)):
                    raise
                if self.logger:
                    self.logger.info(
                        "bridge_queue_write_retry",
                        extra={
                            "extra_fields": {
                                "operation": str(operation_name),
                                "attempt": int(attempt),
                                "max_attempts": int(max_attempts),
                                "reason": str(exc),
                            }
                        },
                    )
                time.sleep(max(0.0, float(base_sleep_seconds)) * (2 ** (attempt - 1)))
        if last_error:
            raise last_error
        return None

    def enqueue(self, action: dict[str, Any]) -> bool:
        return self.enqueue_with_result(action).accepted

    @staticmethod
    def _normalize_action_contract(action: dict[str, Any]) -> dict[str, Any]:
        normalized = dict(action)
        action_type = str(normalized.get("action") or normalized.get("action_type") or "OPEN_MARKET").upper()
        normalized["action_type"] = action_type
        if not str(normalized.get("action") or "").strip():
            normalized["action"] = action_type
        if not str(normalized.get("server_action_id") or "").strip():
            normalized["server_action_id"] = str(normalized.get("signal_id") or "")
        raw_ticket = str(normalized.get("ticket") or "").strip()
        raw_target_ticket = str(normalized.get("target_ticket") or "").strip()
        mirrored_ticket = raw_ticket or raw_target_ticket
        if action_type in {"CLOSE_POSITION", "MODIFY_SLTP", "CLOSE_PARTIAL"} or mirrored_ticket:
            normalized["ticket"] = mirrored_ticket
            normalized["target_ticket"] = mirrored_ticket
        if "volume" in normalized and normalized.get("lot") in {None, "", 0, 0.0}:
            normalized["lot"] = normalized.get("volume")
        if action_type == "CLOSE_PARTIAL":
            close_lot = normalized.get("close_lot")
            lot_value = normalized.get("lot")
            if close_lot in {None, "", 0, 0.0} and lot_value not in {None, "", 0, 0.0}:
                normalized["close_lot"] = lot_value
            elif lot_value in {None, "", 0, 0.0} and close_lot not in {None, "", 0, 0.0}:
                normalized["lot"] = close_lot
        return normalized

    @staticmethod
    def _normalize_action_context(action: dict[str, Any]) -> dict[str, Any]:
        normalized = dict(action)
        raw_context = normalized.get("context_json")
        if isinstance(raw_context, dict):
            context_json = dict(raw_context)
        else:
            try:
                parsed_context = json.loads(str(raw_context or "{}"))
            except Exception:
                parsed_context = {}
            context_json = dict(parsed_context) if isinstance(parsed_context, dict) else {}

        delivery_symbol = str(normalized.get("symbol") or context_json.get("symbol") or "").strip()
        symbol = delivery_symbol.upper()
        symbol_key = _normalize_symbol_key(symbol)
        setup_name = str(normalized.get("setup") or context_json.get("setup") or "").upper()
        strategy_key = str(
            context_json.get("strategy_key")
            or normalized.get("strategy_key")
            or normalized.get("strategy_id")
            or normalized.get("strategy")
            or normalized.get("strategy_family")
            or resolve_strategy_key(symbol_key, setup_name)
        ).strip()
        strategy_state = str(
            context_json.get("strategy_state")
            or normalized.get("strategy_state")
            or "NORMAL"
        ).upper()
        strategy_score = _safe_float(
            context_json.get("strategy_score"),
            _safe_float(
                normalized.get("strategy_score"),
                _safe_float(normalized.get("action_score"), 0.0),
            ),
        )
        strategy_recent_performance = _safe_float(
            context_json.get("strategy_recent_performance"),
            _safe_float(normalized.get("strategy_recent_performance"), 0.0),
        )

        raw_strategy_pool = context_json.get("strategy_pool")
        if not isinstance(raw_strategy_pool, list):
            raw_strategy_pool = normalized.get("strategy_pool")
        strategy_pool = [
            str(item).strip()
            for item in (raw_strategy_pool or [])
            if str(item).strip()
        ]
        if strategy_key and strategy_key not in strategy_pool:
            strategy_pool.insert(0, strategy_key)

        raw_strategy_pool_ranking = context_json.get("strategy_pool_ranking")
        if not isinstance(raw_strategy_pool_ranking, list):
            raw_strategy_pool_ranking = normalized.get("strategy_pool_ranking")
        strategy_pool_ranking = [
            dict(entry)
            for entry in (raw_strategy_pool_ranking or [])
            if isinstance(entry, dict)
        ]
        if strategy_key and not strategy_pool_ranking:
            strategy_pool_ranking = [
                {
                    "strategy_key": strategy_key,
                    "strategy_score": float(strategy_score),
                    "rank_score": float(strategy_score),
                    "strategy_state": strategy_state,
                }
            ]

        strategy_pool_winner = str(
            context_json.get("strategy_pool_winner")
            or normalized.get("strategy_pool_winner")
            or strategy_key
        ).strip()
        winning_strategy_reason = str(
            context_json.get("winning_strategy_reason")
            or normalized.get("winning_strategy_reason")
            or ("active_runtime_strategy" if strategy_pool_winner else "")
        ).strip()

        float_defaults = {
            "strategy_score": float(strategy_score),
            "strategy_recent_performance": float(strategy_recent_performance),
            "regime_fit": _safe_float(
                context_json.get("regime_fit"),
                _safe_float(normalized.get("regime_fit"), 0.0),
            ),
            "session_fit": _safe_float(
                context_json.get("session_fit"),
                _safe_float(normalized.get("session_fit"), 0.0),
            ),
            "volatility_fit": _safe_float(
                context_json.get("volatility_fit"),
                _safe_float(normalized.get("volatility_fit"), 0.0),
            ),
            "pair_behavior_fit": _safe_float(
                context_json.get("pair_behavior_fit"),
                _safe_float(normalized.get("pair_behavior_fit"), 0.0),
            ),
            "execution_quality_fit": _safe_float(
                context_json.get("execution_quality_fit"),
                _safe_float(normalized.get("execution_quality_fit"), 0.0),
            ),
            "entry_timing_score": _safe_float(
                context_json.get("entry_timing_score"),
                _safe_float(normalized.get("entry_timing_score"), 0.0),
            ),
            "structure_cleanliness_score": _safe_float(
                context_json.get("structure_cleanliness_score"),
                _safe_float(normalized.get("structure_cleanliness_score"), 0.0),
            ),
            "tier_size_multiplier": _safe_float(
                context_json.get("tier_size_multiplier"),
                _safe_float(normalized.get("tier_size_multiplier"), 1.0),
            ),
            "delta_proxy_score": _safe_float(
                context_json.get("delta_proxy_score"),
                _safe_float(normalized.get("delta_proxy_score"), 0.0),
            ),
            "compression_expansion_score": _safe_float(
                context_json.get("compression_expansion_score"),
                _safe_float(normalized.get("compression_expansion_score"), 0.0),
            ),
            "transition_momentum": _safe_float(
                context_json.get("transition_momentum"),
                _safe_float(normalized.get("transition_momentum"), 0.0),
            ),
            "transition_momentum_size_multiplier": _safe_float(
                context_json.get("transition_momentum_size_multiplier"),
                _safe_float(normalized.get("transition_momentum_size_multiplier"), 1.0),
            ),
            "compression_burst_size_multiplier": _safe_float(
                context_json.get("compression_burst_size_multiplier"),
                _safe_float(normalized.get("compression_burst_size_multiplier"), 1.0),
            ),
            "confidence_multiplier": _safe_float(
                context_json.get("confidence_multiplier"),
                _safe_float(normalized.get("confidence_multiplier"), 1.0),
            ),
            "velocity_decay": _safe_float(
                context_json.get("velocity_decay"),
                _safe_float(normalized.get("velocity_decay"), 1.0),
            ),
            "velocity_decay_score_penalty": _safe_float(
                context_json.get("velocity_decay_score_penalty"),
                _safe_float(normalized.get("velocity_decay_score_penalty"), 0.0),
            ),
            "velocity_trades_per_10_bars": _safe_float(
                context_json.get("velocity_trades_per_10_bars"),
                _safe_float(normalized.get("velocity_trades_per_10_bars"), 0.0),
            ),
            "btc_velocity_decay": _safe_float(
                context_json.get("btc_velocity_decay"),
                _safe_float(normalized.get("btc_velocity_decay"), 1.0),
            ),
            "correlation_penalty": _safe_float(
                context_json.get("correlation_penalty"),
                _safe_float(normalized.get("correlation_penalty"), 0.0),
            ),
            "family_rotation_penalty": _safe_float(
                context_json.get("family_rotation_penalty"),
                _safe_float(normalized.get("family_rotation_penalty"), 0.0),
            ),
            "session_loosen_factor": _safe_float(
                context_json.get("session_loosen_factor"),
                _safe_float(normalized.get("session_loosen_factor"), 1.0),
            ),
            "actual_rr_achieved": _safe_float(
                context_json.get("actual_rr_achieved"),
                _safe_float(normalized.get("actual_rr_achieved"), 0.0),
            ),
        }
        string_defaults = {
            "symbol": delivery_symbol or symbol,
            "setup": setup_name,
            "strategy_family": strategy_key,
            "strategy_key": strategy_key,
            "strategy_state": strategy_state,
            "management_template": str(
                context_json.get("management_template")
                or normalized.get("management_template")
                or ""
            ),
            "strategy_pool_winner": strategy_pool_winner,
            "winning_strategy_reason": winning_strategy_reason,
            "regime_state": str(
                context_json.get("regime_state")
                or normalized.get("regime_state")
                or normalized.get("regime")
                or ""
            ),
            "session_name": str(
                context_json.get("session_name")
                or normalized.get("session_name")
                or ""
            ),
            "market_data_source": str(
                context_json.get("market_data_source")
                or normalized.get("market_data_source")
                or ""
            ),
            "market_data_consensus_state": str(
                context_json.get("market_data_consensus_state")
                or normalized.get("market_data_consensus_state")
                or ""
            ),
            "session_stop_state": str(
                context_json.get("session_stop_state")
                or normalized.get("session_stop_state")
                or ""
            ),
            "session_stop_reason": str(
                context_json.get("session_stop_reason")
                or normalized.get("session_stop_reason")
                or ""
            ),
            "xau_grid_mode": str(
                context_json.get("xau_grid_mode")
                or normalized.get("xau_grid_mode")
                or normalized.get("grid_mode")
                or ""
            ),
            "quality_tier": str(
                context_json.get("quality_tier")
                or normalized.get("quality_tier")
                or ""
            ),
            "compression_proxy_state": str(
                context_json.get("compression_proxy_state")
                or normalized.get("compression_proxy_state")
                or ""
            ),
            "recycle_origin_session": str(
                context_json.get("recycle_origin_session")
                or normalized.get("recycle_origin_session")
                or ""
            ),
            "equity_momentum_mode": str(
                context_json.get("equity_momentum_mode")
                or normalized.get("equity_momentum_mode")
                or "NEUTRAL"
            ),
            "verified_reason_code": str(
                context_json.get("verified_reason_code")
                or normalized.get("verified_reason_code")
                or ""
            ),
            "verified_reason_text": str(
                context_json.get("verified_reason_text")
                or normalized.get("verified_reason_text")
                or ""
            ),
            "approved_rr_target": str(
                context_json.get("approved_rr_target")
                or normalized.get("approved_rr_target")
                or ""
            ),
            "dynamic_rr_band": str(
                context_json.get("dynamic_rr_band")
                or normalized.get("dynamic_rr_band")
                or normalized.get("approved_rr_target")
                or ""
            ),
            "streak_adjust_mode": str(
                context_json.get("streak_adjust_mode")
                or normalized.get("streak_adjust_mode")
                or "NEUTRAL"
            ),
            "manager_reason": str(
                context_json.get("manager_reason")
                or normalized.get("manager_reason")
                or ""
            ),
        }
        bool_defaults = {
            "throughput_recovery_active": bool(
                context_json.get("throughput_recovery_active")
                if "throughput_recovery_active" in context_json
                else normalized.get("throughput_recovery_active", False)
            ),
            "recycle_session": bool(
                context_json.get("recycle_session")
                if "recycle_session" in context_json
                else normalized.get("recycle_session", False)
            ),
            "btc_weekend_mode": bool(
                context_json.get("btc_weekend_mode")
                if "btc_weekend_mode" in context_json
                else normalized.get("btc_weekend_mode", False)
            ),
        }

        # Strategy identity must survive end-to-end even if the producer supplied
        # empty placeholders in context_json. Blank values are treated as missing.
        for key, value in string_defaults.items():
            if value and not str(context_json.get(key) or "").strip():
                context_json[key] = value
        for key, value in float_defaults.items():
            existing_value = context_json.get(key)
            if existing_value in {None, "", "null"}:
                context_json[key] = float(value)
        for key, value in bool_defaults.items():
            if key not in context_json:
                context_json[key] = bool(value)
        if strategy_pool and not isinstance(context_json.get("strategy_pool"), list):
            context_json["strategy_pool"] = list(strategy_pool)
        elif strategy_pool and not context_json.get("strategy_pool"):
            context_json["strategy_pool"] = list(strategy_pool)
        if strategy_pool_ranking and not isinstance(context_json.get("strategy_pool_ranking"), list):
            context_json["strategy_pool_ranking"] = list(strategy_pool_ranking)
        elif strategy_pool_ranking and not context_json.get("strategy_pool_ranking"):
            context_json["strategy_pool_ranking"] = list(strategy_pool_ranking)

        normalized["context_json"] = context_json
        return normalized

    @staticmethod
    def _normalize_existing_action_contracts(connection: sqlite3.Connection) -> None:
        connection.execute(
            """
            UPDATE bridge_actions
            SET action_type = UPPER(COALESCE(NULLIF(TRIM(action_type), ''), NULLIF(TRIM(action), ''), 'OPEN_MARKET')),
                action = UPPER(COALESCE(NULLIF(TRIM(action), ''), NULLIF(TRIM(action_type), ''), 'OPEN_MARKET'))
            """
        )
        connection.execute(
            """
            UPDATE bridge_actions
            SET ticket = COALESCE(NULLIF(TRIM(ticket), ''), NULLIF(TRIM(target_ticket), ''), ''),
                target_ticket = COALESCE(NULLIF(TRIM(target_ticket), ''), NULLIF(TRIM(ticket), ''), '')
            WHERE UPPER(COALESCE(NULLIF(TRIM(action_type), ''), NULLIF(TRIM(action), ''), 'OPEN_MARKET'))
                  IN ('CLOSE_POSITION', 'MODIFY_SLTP', 'CLOSE_PARTIAL')
               OR NULLIF(TRIM(ticket), '') IS NOT NULL
               OR NULLIF(TRIM(target_ticket), '') IS NOT NULL
            """
        )

    def enqueue_with_result(self, action: dict[str, Any]) -> EnqueueResult:
        action = self._normalize_action_context(self._normalize_action_contract(action))
        signal_id = str(action.get("signal_id", "")).strip()
        if not signal_id:
            return EnqueueResult(False, "missing_signal_id", signal_id=signal_id)
        action_type = str(action.get("action") or action.get("action_type") or "OPEN_MARKET").upper()
        target_ticket = str(action.get("target_ticket") or "")
        ticket_value = str(action.get("ticket") or target_ticket or "")
        target_account = str(action.get("target_account") or "").strip()
        target_magic_raw = action.get("target_magic")
        target_magic = int(target_magic_raw) if target_magic_raw not in {None, "", 0, "0"} else None
        symbol = str(action.get("symbol", "")).upper()
        symbol_key = _normalize_symbol_key(symbol)
        timeframe = str(action.get("tf") or action.get("timeframe") or "M5").upper()
        dedupe_key = str(action.get("dedupe_key") or self._build_dedupe_key(action, timeframe))
        now = _iso_now()
        expires = _to_iso(utc_now() + timedelta(seconds=max(1, self.ttl_seconds)))
        active_statuses = {"QUEUED", "DELIVERED", "ACKED", "EXECUTED", "PENDING"}
        terminal_statuses = {"EXPIRED", "CLOSED", "CANCELLED", "FAILED_VALIDATION", "REJECTED"}
        setup_name = str(action.get("setup", "")).upper()
        is_grid_open = action_type == "OPEN_MARKET" and self._is_grid_setup(setup_name)
        with self._connect() as connection:
            existing = connection.execute(
                """
                SELECT status
                FROM bridge_actions
                WHERE signal_id = ?
                """,
                (signal_id,),
            ).fetchone()
            if existing and str(existing[0]).upper() not in terminal_statuses:
                existing_status = str(existing[0]).upper()
                if existing_status == "QUEUED" and action_type in {"OPEN_MARKET", "MODIFY_SLTP"}:
                    connection.execute(
                        """
                        UPDATE bridge_actions
                        SET symbol = ?,
                            symbol_key = ?,
                            target_ticket = ?,
                            ticket = ?,
                            side = ?,
                            lot = ?,
                            sl = ?,
                            tp = ?,
                            max_slippage_points = ?,
                            expiry_utc = ?,
                            reason = ?,
                            ai_summary = ?,
                            trailing_json = ?,
                            breakeven_json = ?,
                            partials_json = ?,
                            mode = ?,
                            setup = ?,
                            regime = ?,
                            probability = ?,
                            expected_value_r = ?,
                            news_status = ?,
                            final_decision_json = ?,
                            context_json = ?,
                            entry_price = ?,
                            dedupe_key = ?,
                            tf = ?,
                            target_account = ?,
                            target_magic = ?,
                            updated_at = ?
                        WHERE signal_id = ?
                        """,
                        (
                            symbol,
                            symbol_key,
                            target_ticket,
                            ticket_value,
                            str(action.get("side", "")).upper(),
                            float(action.get("lot", 0.0)),
                            float(action.get("sl", 0.0)),
                            float(action.get("tp", 0.0)),
                            int(action.get("max_slippage_points", 0)),
                            str(action.get("expiry_utc") or expires),
                            str(action.get("reason", "")),
                            json.dumps(action.get("ai_summary") or {}, sort_keys=True),
                            json.dumps(action.get("trailing") or {}, sort_keys=True),
                            json.dumps(action.get("breakeven") or {}, sort_keys=True),
                            json.dumps(action.get("partials") or [], sort_keys=True),
                            str(action.get("mode", "DEMO")).upper(),
                            str(action.get("setup", "")),
                            str(action.get("regime", "")),
                            float(action.get("probability", 0.0)),
                            float(action.get("expected_value_r", 0.0)),
                            str(action.get("news_status", "")),
                            str(action.get("final_decision_json", "")),
                            json.dumps(action.get("context_json") or {}, sort_keys=True),
                            float(action.get("entry_price", 0.0)),
                            dedupe_key,
                            timeframe,
                            target_account,
                            target_magic,
                            now,
                            signal_id,
                        ),
                    )
                    connection.commit()
                    return EnqueueResult(True, "updated_existing_queued", signal_id=signal_id)
                return EnqueueResult(False, "signal_already_active", signal_id=signal_id)
            dedupe_existing = connection.execute(
                """
                SELECT signal_id, status
                FROM bridge_actions
                WHERE dedupe_key = ?
                ORDER BY created_at DESC
                LIMIT 1
                """,
                (dedupe_key,),
            ).fetchone()
            if dedupe_existing and str(dedupe_existing[0]) != signal_id and str(dedupe_existing[1]).upper() in active_statuses:
                if is_grid_open:
                    existing_row = connection.execute(
                        """
                        SELECT entry_price
                        FROM bridge_actions
                        WHERE signal_id = ?
                        """,
                        (str(dedupe_existing[0]),),
                    ).fetchone()
                    current_entry = float(action.get("entry_price") or 0.0)
                    prior_entry = float(existing_row[0]) if existing_row else 0.0
                    point = self._symbol_point(symbol_key)
                    step_points = max(1.0, float(action.get("grid_step_points_hint") or action.get("grid_step_points") or 35.0))
                    step_price = step_points * point
                    if current_entry > 0 and prior_entry > 0 and abs(current_entry - prior_entry) >= step_price:
                        pass
                    else:
                        return EnqueueResult(False, "grid_step_not_reached", signal_id=signal_id)
                else:
                    return EnqueueResult(False, "dedupe_active", signal_id=signal_id)
            if action_type == "OPEN_MARKET":
                if self.open_enqueue_cooldown_seconds > 0:
                    recent_cutoff = _to_iso(utc_now() - timedelta(seconds=max(1, int(self.open_enqueue_cooldown_seconds))))
                    recent = connection.execute(
                        """
                        SELECT signal_id
                        FROM bridge_actions
                        WHERE symbol_key = ?
                          AND action_type = 'OPEN_MARKET'
                          AND status IN ('QUEUED', 'DELIVERED', 'ACKED', 'EXECUTED')
                          AND created_at >= ?
                        ORDER BY created_at DESC
                        LIMIT 1
                        """,
                        (symbol_key, recent_cutoff),
                    ).fetchone()
                    if recent:
                        return EnqueueResult(False, "open_enqueue_cooldown", signal_id=signal_id)
                open_rows = connection.execute(
                    """
                    SELECT signal_id
                    FROM bridge_actions
                    WHERE symbol_key = ?
                      AND action_type = 'OPEN_MARKET'
                      AND status = 'QUEUED'
                    ORDER BY created_at ASC
                    """,
                    (symbol_key,),
                ).fetchall()
                cap = max(1, int(self.max_open_queue_per_symbol))
                while len(open_rows) >= cap:
                    oldest = str(open_rows[0][0])
                    connection.execute(
                        """
                        UPDATE bridge_actions
                        SET status = 'CANCELLED',
                            last_error = 'queue_cap_compacted',
                            updated_at = ?
                        WHERE signal_id = ?
                        """,
                        (now, oldest),
                    )
                    open_rows = open_rows[1:]
            connection.execute(
                """
                INSERT OR REPLACE INTO bridge_actions (
                    signal_id, action_type, target_ticket, symbol, symbol_key, side, lot, sl, tp, max_slippage_points,
                    expiry_utc, reason, ai_summary, trailing_json, breakeven_json, partials_json,
                    mode, setup, regime, probability, expected_value_r, news_status, final_decision_json, context_json,
                    entry_price, created_at, updated_at, status, pull_count, last_pull_at, ticket, dedupe_key, tf,
                    validation_json, last_error, confluence_score, action_score, risk_cost, delivered_at, lease_until_utc, acked_at,
                    delivered_account, delivered_magic, target_account, target_magic
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    signal_id,
                    action_type,
                    target_ticket,
                    symbol,
                    symbol_key,
                    str(action.get("side", "")).upper(),
                    float(action.get("lot", 0.0)),
                    float(action.get("sl", 0.0)),
                    float(action.get("tp", 0.0)),
                    int(action.get("max_slippage_points", 0)),
                    str(action.get("expiry_utc") or expires),
                    str(action.get("reason", "")),
                    json.dumps(action.get("ai_summary") or {}, sort_keys=True),
                    json.dumps(action.get("trailing") or {}, sort_keys=True),
                    json.dumps(action.get("breakeven") or {}, sort_keys=True),
                    json.dumps(action.get("partials") or [], sort_keys=True),
                    str(action.get("mode", "DEMO")).upper(),
                    str(action.get("setup", "")),
                    str(action.get("regime", "")),
                    float(action.get("probability", 0.0)),
                    float(action.get("expected_value_r", 0.0)),
                    str(action.get("news_status", "")),
                    str(action.get("final_decision_json", "")),
                    json.dumps(action.get("context_json") or {}, sort_keys=True),
                    float(action.get("entry_price", 0.0)),
                    now,
                    now,
                    "QUEUED",
                    0,
                    None,
                    ticket_value or None,
                    dedupe_key,
                    timeframe,
                    json.dumps(action.get("validation_snapshot") or {}, sort_keys=True),
                    str(action.get("last_error", "")),
                    float(action.get("confluence_score", 0.0)),
                    float(action.get("action_score", 0.0)),
                    float(action.get("risk_cost", 0.0)),
                    None,
                    None,
                    None,
                    "",
                    None,
                    target_account,
                    target_magic,
                ),
            )
            connection.commit()
        return EnqueueResult(True, "enqueued", signal_id=signal_id)

    def has_signal(self, signal_id: str) -> bool:
        with self._connect() as connection:
            row = connection.execute(
                "SELECT 1 FROM bridge_actions WHERE signal_id = ? AND status NOT IN ('EXPIRED', 'CLOSED', 'CANCELLED', 'FAILED_VALIDATION', 'REJECTED')",
                (signal_id,),
            ).fetchone()
        return row is not None

    def count_active_actions(
        self,
        *,
        action_type: str | None = None,
        target_ticket: str | None = None,
        signal_prefix: str | None = None,
    ) -> int:
        clauses = ["status IN ('QUEUED', 'DELIVERED', 'ACKED', 'EXECUTED', 'PENDING')"]
        params: list[Any] = []
        if action_type:
            clauses.append("action_type = ?")
            params.append(str(action_type).upper())
        if target_ticket:
            clauses.append("COALESCE(NULLIF(TRIM(target_ticket), ''), NULLIF(TRIM(ticket), '')) = ?")
            params.append(str(target_ticket))
        if signal_prefix:
            clauses.append("signal_id LIKE ?")
            params.append(f"{signal_prefix}%")
        query = f"SELECT COUNT(1) FROM bridge_actions WHERE {' AND '.join(clauses)}"
        with self._connect() as connection:
            row = connection.execute(query, tuple(params)).fetchone()
        return int(row[0]) if row else 0

    def pull(
        self,
        symbol: str,
        account: str,
        magic: int,
        limit: int = 10,
        include_delivered: bool = False,
        allow_redelivery: bool = False,
        lease_seconds: int = 10,
    ) -> list[dict[str, Any]]:
        self.expire_old()
        self.cleanup_expired_locks()
        rows = self.fetch_candidates(
            symbol=symbol,
            timeframe=None,
            account=account,
            magic=magic,
            include_delivered=bool(include_delivered),
            limit=max(1, int(limit)),
        )
        for row in rows:
            action_type = str(row["action_type"] or "OPEN_MARKET").upper()
            symbol_key = _normalize_symbol_key(str(row["symbol"] or symbol))
            if action_type == "OPEN_MARKET" and self.has_open_lock(account=account, magic=magic, symbol_key=symbol_key):
                continue
            if not self.mark_delivered(
                signal_id=str(row["signal_id"]),
                account=account,
                magic=magic,
                allow_redelivery=bool(allow_redelivery),
                lease_seconds=max(1, int(lease_seconds)),
            ):
                continue
            action = self._row_to_action(row=row, account=account, magic=magic, requested_symbol=symbol)
            if action_type == "OPEN_MARKET":
                self.acquire_open_lock(account=account, magic=magic, symbol_key=symbol_key, action_id=str(row["signal_id"]))
            return [action]
        return []

    def fetch_candidates(
        self,
        symbol: str,
        timeframe: str | None = None,
        account: str | None = None,
        magic: int | None = None,
        include_delivered: bool = False,
        limit: int = 25,
    ) -> list[sqlite3.Row]:
        self.expire_old()
        symbol_key = _normalize_symbol_key(symbol)
        now_iso = _iso_now()
        params: list[Any] = [symbol_key, now_iso]
        status_clause = "status = 'QUEUED'"
        tf_clause = ""
        account_scope_clause = ""
        if timeframe:
            tf_clause = "AND (UPPER(tf) = ? OR tf IS NULL OR TRIM(tf) = '')"
            params.append(str(timeframe).upper())
        if account is not None and magic is not None:
            account_scope_clause = (
                "AND (target_account IS NULL OR TRIM(target_account) = '' OR target_account = ?) "
                "AND (target_magic IS NULL OR target_magic = ?)"
            )
            params.extend([str(account), int(magic)])
        if include_delivered:
            if account is not None and magic is not None:
                status_clause = (
                    "(status = 'QUEUED' OR (status = 'DELIVERED' AND lease_until_utc IS NOT NULL "
                    "AND lease_until_utc <= ? AND delivered_account = ? AND delivered_magic = ?))"
                )
                params.extend([now_iso, str(account), int(magic)])
            else:
                status_clause = "(status = 'QUEUED' OR (status = 'DELIVERED' AND lease_until_utc IS NOT NULL AND lease_until_utc <= ?))"
                params.append(now_iso)
        params.append(max(1, int(limit)))
        with self._connect(row_factory=True) as connection:
            rows = connection.execute(
                f"""
                SELECT *
                FROM bridge_actions
                WHERE symbol_key = ?
                  AND expiry_utc > ?
                  {tf_clause}
                  {account_scope_clause}
                  AND {status_clause}
                ORDER BY created_at ASC, signal_id ASC
                LIMIT ?
                """,
                tuple(params),
            ).fetchall()
        return rows

    def update_validation(
        self,
        signal_id: str,
        *,
        normalized_sl: float | None,
        normalized_tp: float | None,
        validation_snapshot: dict[str, Any],
        max_slippage_points: int | None = None,
    ) -> None:
        now = _iso_now()
        with self._connect() as connection:
            connection.execute(
                """
                UPDATE bridge_actions
                SET sl = ?,
                    tp = ?,
                    validation_json = ?,
                    max_slippage_points = COALESCE(?, max_slippage_points),
                    updated_at = ?
                WHERE signal_id = ?
                """,
                (
                    float(normalized_sl) if normalized_sl is not None else 0.0,
                    float(normalized_tp) if normalized_tp is not None else 0.0,
                    json.dumps(validation_snapshot, sort_keys=True),
                    int(max_slippage_points) if max_slippage_points is not None else None,
                    now,
                    signal_id,
                ),
            )
            connection.commit()

    def mark_failed_validation(self, signal_id: str, reason: str, snapshot: dict[str, Any]) -> None:
        now = _iso_now()
        with self._connect() as connection:
            connection.execute(
                """
                UPDATE bridge_actions
                SET status = 'FAILED_VALIDATION',
                    validation_json = ?,
                    last_error = ?,
                    updated_at = ?
                WHERE signal_id = ?
                """,
                (json.dumps(snapshot, sort_keys=True), str(reason), now, signal_id),
            )
            connection.commit()

    def mark_cancelled(self, signal_id: str, reason: str) -> None:
        now = _iso_now()
        with self._connect() as connection:
            connection.execute(
                """
                UPDATE bridge_actions
                SET status = 'CANCELLED',
                    last_error = ?,
                    updated_at = ?
                WHERE signal_id = ?
                """,
                (str(reason), now, signal_id),
            )
            connection.commit()

    def update_scoring(self, signal_id: str, *, confluence_score: float, action_score: float, risk_cost: float, reason: str) -> None:
        now = _iso_now()
        with self._connect() as connection:
            connection.execute(
                """
                UPDATE bridge_actions
                SET confluence_score = ?,
                    action_score = ?,
                    risk_cost = ?,
                    reason = ?,
                    updated_at = ?
                WHERE signal_id = ?
                """,
                (
                    float(confluence_score),
                    float(action_score),
                    float(risk_cost),
                    str(reason),
                    now,
                    signal_id,
                ),
            )
            connection.commit()

    def mark_delivered(
        self,
        signal_id: str,
        account: str,
        magic: int,
        dry_run: bool = False,
        allow_redelivery: bool = False,
        lease_seconds: int = 10,
    ) -> bool:
        if dry_run:
            return True
        now_dt = utc_now()
        now = _to_iso(now_dt)
        lease_until = _to_iso(now_dt + timedelta(seconds=max(1, int(lease_seconds))))
        status_clause = "status = 'QUEUED'"
        params: list[Any] = [lease_until, now, str(account), int(magic), now, now, signal_id]
        if allow_redelivery:
            status_clause = "(status = 'QUEUED' OR (status = 'DELIVERED' AND lease_until_utc IS NOT NULL AND lease_until_utc <= ? AND delivered_account = ? AND delivered_magic = ?))"
            params.extend([now, str(account), int(magic)])
        with self._connect() as connection:
            cursor = connection.execute(
                f"""
                UPDATE bridge_actions
                SET status = 'DELIVERED',
                    lease_until_utc = ?,
                    delivered_at = ?,
                    delivered_account = ?,
                    delivered_magic = ?,
                    last_pull_at = ?,
                    pull_count = pull_count + 1,
                    updated_at = ?
                WHERE signal_id = ?
                  AND {status_clause}
                """,
                tuple(params),
            )
            connection.commit()
        return cursor.rowcount > 0

    def ack_action(self, signal_id: str, status: str = "ACKED", note: str = "") -> bool:
        normalized_status = str(status or "ACKED").upper()
        if normalized_status not in {"ACKED", "CANCELLED", "REJECTED", "FAILED_VALIDATION"}:
            normalized_status = "ACKED"
        now = _iso_now()
        with self._connect() as connection:
            row = connection.execute(
                "SELECT delivered_account, delivered_magic, symbol_key, action_type FROM bridge_actions WHERE signal_id = ?",
                (signal_id,),
            ).fetchone()
            if row is None:
                return False
            cursor = connection.execute(
                """
                UPDATE bridge_actions
                SET status = ?,
                    acked_at = CASE WHEN ? = 'ACKED' THEN ? ELSE acked_at END,
                    last_error = CASE WHEN ? IN ('CANCELLED', 'REJECTED', 'FAILED_VALIDATION') THEN ? ELSE last_error END,
                    updated_at = ?
                WHERE signal_id = ?
                  AND status IN ('DELIVERED', 'QUEUED')
                """,
                (normalized_status, normalized_status, now, normalized_status, str(note or ""), now, signal_id),
            )
            if cursor.rowcount > 0:
                account = str(row[0] or "").strip()
                symbol_key = str(row[2] or "")
                action_type = str(row[3] or "OPEN_MARKET").upper()
                if account and action_type == "OPEN_MARKET":
                    connection.execute(
                        """
                        DELETE FROM bridge_delivery_locks
                        WHERE account = ?
                          AND magic = ?
                          AND symbol_key = ?
                          AND action_type = 'OPEN_MARKET'
                        """,
                        (account, int(row[1] or 0), symbol_key),
                    )
            connection.commit()
        return cursor.rowcount > 0

    def has_open_lock(self, account: str, magic: int, symbol_key: str) -> bool:
        now_iso = _iso_now()
        with self._connect() as connection:
            row = connection.execute(
                """
                SELECT 1
                FROM bridge_delivery_locks
                WHERE account = ?
                  AND magic = ?
                  AND symbol_key = ?
                  AND action_type = 'OPEN_MARKET'
                  AND expires_at > ?
                LIMIT 1
                """,
                (str(account), int(magic), str(symbol_key), now_iso),
            ).fetchone()
        return row is not None

    def active_open_lock_count(self, account: str, magic: int) -> int:
        now_iso = _iso_now()
        with self._connect() as connection:
            row = connection.execute(
                """
                SELECT COUNT(*)
                FROM bridge_delivery_locks
                WHERE account = ?
                  AND magic = ?
                  AND action_type = 'OPEN_MARKET'
                  AND expires_at > ?
                """,
                (str(account), int(magic), now_iso),
            ).fetchone()
        return int(row[0]) if row else 0

    def acquire_open_lock(self, account: str, magic: int, symbol_key: str, action_id: str, lock_seconds: int = 20) -> None:
        now = utc_now()
        expires = now + timedelta(seconds=max(1, int(lock_seconds)))
        with self._connect() as connection:
            connection.execute(
                """
                INSERT INTO bridge_delivery_locks (
                    account, magic, symbol_key, action_type, action_id, created_at, expires_at
                ) VALUES (?, ?, ?, 'OPEN_MARKET', ?, ?, ?)
                ON CONFLICT(account, magic, symbol_key, action_type)
                DO UPDATE SET
                    action_id = excluded.action_id,
                    created_at = excluded.created_at,
                    expires_at = excluded.expires_at
                """,
                (str(account), int(magic), str(symbol_key), str(action_id), _to_iso(now), _to_iso(expires)),
            )
            connection.commit()

    def release_open_lock(self, account: str, magic: int, symbol_key: str) -> None:
        with self._connect() as connection:
            connection.execute(
                """
                DELETE FROM bridge_delivery_locks
                WHERE account = ?
                  AND magic = ?
                  AND symbol_key = ?
                  AND action_type = 'OPEN_MARKET'
                """,
                (str(account), int(magic), str(symbol_key)),
            )
            connection.commit()

    def cleanup_expired_locks(self) -> None:
        now_iso = _iso_now()
        self._execute_write_with_retry(
            "cleanup_expired_locks",
            lambda connection: connection.execute(
                "DELETE FROM bridge_delivery_locks WHERE expires_at <= ?",
                (now_iso,),
            ),
        )

    def clear_all_locks(self) -> int:
        cursor = self._execute_write_with_retry(
            "clear_all_locks",
            lambda connection: connection.execute("DELETE FROM bridge_delivery_locks"),
        )
        return int(cursor.rowcount)

    def cancel_stale_delivered(
        self,
        max_age_seconds: int = 60,
        *,
        retry_limit: int = 0,
        requeue_grace_seconds: int = 0,
    ) -> int:
        now_dt = utc_now()
        cutoff = _to_iso(now_dt - timedelta(seconds=max(5, int(max_age_seconds))))
        proof_cutoff = _to_iso(now_dt - timedelta(seconds=max(10, min(int(max_age_seconds), 25))))
        now_iso = _to_iso(now_dt)
        expiry_cutoff_iso = _to_iso(now_dt - timedelta(seconds=max(0, int(requeue_grace_seconds))))
        requeued = 0
        if int(retry_limit) > 0:
            retry_cursor = self._execute_write_with_retry(
                "requeue_stale_delivered",
                lambda connection: connection.execute(
                    """
                    UPDATE bridge_actions
                    SET status = 'QUEUED',
                        last_error = 'delivery_report_timeout_requeued',
                        lease_until_utc = NULL,
                        delivered_at = NULL,
                        delivered_account = '',
                        delivered_magic = NULL,
                        updated_at = ?
                    WHERE status = 'DELIVERED'
                      AND action_type = 'OPEN_MARKET'
                      AND delivered_at IS NOT NULL
                      AND (
                            delivered_at <= ?
                            OR (
                                (signal_id LIKE 'CANARY::%' OR signal_id LIKE 'FORCE_TEST::%')
                                AND delivered_at <= ?
                            )
                          )
                      AND expiry_utc <= ?
                      AND COALESCE(execution_report_json, '') = ''
                      AND COALESCE(acked_at, '') = ''
                      AND pull_count < ?
                    """,
                    (now_iso, cutoff, proof_cutoff, expiry_cutoff_iso, int(retry_limit)),
                ),
            )
            requeued = int(retry_cursor.rowcount)
        cancel_cursor = self._execute_write_with_retry(
            "cancel_stale_delivered",
            lambda connection: connection.execute(
                """
                UPDATE bridge_actions
                SET status = 'CANCELLED',
                    last_error = CASE
                        WHEN action_type = 'OPEN_MARKET' THEN 'delivery_lock_timeout'
                        ELSE 'delivery_report_timeout'
                    END,
                    lease_until_utc = NULL,
                    updated_at = ?
                WHERE status = 'DELIVERED'
                  AND delivered_at IS NOT NULL
                  AND (
                        delivered_at <= ?
                        OR (
                            (signal_id LIKE 'CANARY::%' OR signal_id LIKE 'FORCE_TEST::%')
                            AND delivered_at <= ?
                        )
                      )
                  AND expiry_utc <= ?
                """,
                (now_iso, cutoff, proof_cutoff, now_iso),
            ),
        )
        return int(cancel_cursor.rowcount) + int(requeued)

    def startup_revalidate(self, *, ttl_seconds: int = 120) -> dict[str, int]:
        now_ts = utc_now()
        summary = {
            "found": 0,
            "queued": 0,
            "delivered": 0,
            "expired": 0,
            "blocked": 0,
            "preserved": 0,
            "locks_cleared": 0,
        }
        with self._connect(row_factory=True) as connection:
            rows = connection.execute(
                """
                SELECT signal_id, status, created_at, updated_at, delivered_at
                FROM bridge_actions
                WHERE status IN ('QUEUED', 'DELIVERED', 'PENDING')
                ORDER BY created_at ASC
                """
            ).fetchall()
        summary["found"] = len(rows)
        update_rows: list[tuple[str, str]] = []
        ttl_cutoff = max(30, int(ttl_seconds))
        for row in rows:
            status_value = str(row["status"] or "").upper()
            if status_value == "QUEUED":
                summary["queued"] += 1
            elif status_value == "DELIVERED":
                summary["delivered"] += 1
            age_seconds = 0.0
            for key in ("updated_at", "delivered_at", "created_at"):
                raw_value = str(row[key] or "").strip()
                if not raw_value:
                    continue
                try:
                    age_seconds = max(0.0, (now_ts - _parse_iso(raw_value)).total_seconds())
                    break
                except Exception:
                    continue
            if age_seconds >= float(ttl_cutoff):
                update_rows.append((str(row["signal_id"]), "startup_queue_ttl_expired"))
                summary["expired"] += 1
            else:
                update_rows.append((str(row["signal_id"]), "startup_queue_revalidate_blocked"))
                summary["blocked"] += 1

        now_iso = _to_iso(now_ts)

        def _apply(connection: sqlite3.Connection) -> int:
            updated = 0
            for signal_id, reason in update_rows:
                cursor = connection.execute(
                    """
                    UPDATE bridge_actions
                    SET status = 'CANCELLED',
                        last_error = ?,
                        lease_until_utc = NULL,
                        updated_at = ?
                    WHERE signal_id = ?
                      AND status IN ('QUEUED', 'DELIVERED', 'PENDING')
                    """,
                    (str(reason), now_iso, str(signal_id)),
                )
                updated += int(cursor.rowcount)
            return updated

        if update_rows:
            self._execute_write_with_retry("startup_revalidate", _apply)
        summary["locks_cleared"] = self.clear_all_locks()
        return summary

    def delivered_action_count(
        self,
        account: str,
        magic: int,
        symbol_key: str | None = None,
        *,
        window_minutes: int = 60,
        open_only: bool = False,
    ) -> int:
        cutoff = _to_iso(utc_now() - timedelta(minutes=max(1, int(window_minutes))))
        params: list[Any] = [str(account), int(magic), cutoff]
        symbol_clause = ""
        if symbol_key:
            symbol_clause = "AND symbol_key = ?"
            params.append(str(symbol_key))
        open_clause = "AND action_type = 'OPEN_MARKET'" if open_only else ""
        with self._connect() as connection:
            row = connection.execute(
                f"""
                SELECT COUNT(*)
                FROM bridge_actions
                WHERE delivered_account = ?
                  AND delivered_magic = ?
                  AND delivered_at >= ?
                  {open_clause}
                  {symbol_clause}
                """,
                tuple(params),
            ).fetchone()
        return int(row[0]) if row else 0

    def hourly_delivered_count(self, account: str, magic: int, symbol_key: str | None = None, window_minutes: int = 60) -> int:
        return self.delivered_action_count(
            account=account,
            magic=magic,
            symbol_key=symbol_key,
            window_minutes=window_minutes,
            open_only=True,
        )

    def last_delivered_at(self, account: str, magic: int, symbol_key: str | None = None) -> datetime | None:
        params: list[Any] = [str(account), int(magic)]
        symbol_clause = ""
        if symbol_key:
            symbol_clause = "AND symbol_key = ?"
            params.append(str(symbol_key))
        with self._connect() as connection:
            row = connection.execute(
                f"""
                SELECT delivered_at
                FROM bridge_actions
                WHERE delivered_account = ?
                  AND delivered_magic = ?
                  AND action_type = 'OPEN_MARKET'
                  AND delivered_at IS NOT NULL
                  {symbol_clause}
                ORDER BY delivered_at DESC
                LIMIT 1
                """,
                tuple(params),
            ).fetchone()
        if row is None or not row[0]:
            return None
        return _parse_iso(str(row[0]))

    def update_account_snapshot(
        self,
        *,
        account: str,
        symbol: str,
        magic: int,
        balance: float | None,
        equity: float | None,
        free_margin: float | None,
        extras: dict[str, Any] | None = None,
    ) -> None:
        account_id = str(account).strip()
        if not account_id:
            return
        snapshot_meta = _clean_snapshot_meta(extras)
        if balance is None and equity is None and free_margin is None and not snapshot_meta:
            return
        now = _iso_now()
        with self._connect() as connection:
            connection.execute(
                """
                INSERT INTO bridge_account_state (
                    account, symbol_key, magic, balance, equity, free_margin, meta_json, updated_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(account, symbol_key, magic)
                DO UPDATE SET
                    balance = excluded.balance,
                    equity = excluded.equity,
                    free_margin = excluded.free_margin,
                    meta_json = excluded.meta_json,
                    updated_at = excluded.updated_at
                """,
                (
                    account_id,
                    _normalize_symbol_key(symbol),
                    int(magic),
                    float(balance) if balance is not None else None,
                    float(equity) if equity is not None else None,
                    float(free_margin) if free_margin is not None else None,
                    json.dumps(snapshot_meta, sort_keys=True),
                    now,
                ),
            )
            connection.commit()

    def get_account_snapshot(self, *, account: str, symbol: str, magic: int) -> dict[str, Any] | None:
        account_id = str(account).strip()
        if not account_id:
            return None
        with self._connect(row_factory=True) as connection:
            row = connection.execute(
                """
                SELECT account, symbol_key, magic, balance, equity, free_margin, meta_json, updated_at
                FROM bridge_account_state
                WHERE account = ?
                  AND symbol_key = ?
                  AND magic = ?
                LIMIT 1
                """,
                (account_id, _normalize_symbol_key(symbol), int(magic)),
            ).fetchone()
        if row is None:
            return None
        payload = {
            "account": str(row["account"]),
            "symbol_key": str(row["symbol_key"]),
            "magic": int(row["magic"]),
            "balance": float(row["balance"]) if row["balance"] is not None else None,
            "equity": float(row["equity"]) if row["equity"] is not None else None,
            "free_margin": float(row["free_margin"]) if row["free_margin"] is not None else None,
            "updated_at": str(row["updated_at"]),
        }
        try:
            payload.update(_clean_snapshot_meta(json.loads(str(row["meta_json"] or "{}"))))
        except Exception:
            pass
        return payload

