def _build_dashboard_policy(
    config: dict[str, Any] | None = None,
    *,
    default_host: str = "127.0.0.1",
    default_port: int = 8000,
) -> DashboardPolicy:
    payload = config if isinstance(config, dict) else {}
    password = _env_first(("APEX_DASHBOARD_PASSWORD", "DASHBOARD_PASSWORD"), str(payload.get("password", "")).strip())
    session_secret = _env_first(("APEX_DASHBOARD_SESSION_SECRET", "DASHBOARD_SESSION_SECRET"), str(payload.get("session_secret", "")).strip())
    host_value = str(payload.get("host", default_host) or default_host).strip() or default_host
    port_value = max(1, int(payload.get("port", default_port)))
    bind_host_value = str(payload.get("bind_host", host_value) or host_value).strip() or host_value
    bind_port_value = max(1, int(payload.get("bind_port", port_value)))
    allowed_ips_raw = payload.get("allowed_ips", [])
    if isinstance(allowed_ips_raw, str):
        allowed_ips = tuple(part.strip() for part in allowed_ips_raw.split(",") if part.strip())
    elif isinstance(allowed_ips_raw, (list, tuple, set)):
        allowed_ips = tuple(str(item).strip() for item in allowed_ips_raw if str(item).strip())
    else:
        allowed_ips = ()
    return DashboardPolicy(
        enabled=bool(payload.get("enabled", True)),
        host=host_value,
        port=port_value,
        bind_host=bind_host_value,
        bind_port=bind_port_value,
        public_enabled=bool(payload.get("public_enabled", False)),
        allow_public_health=bool(payload.get("allow_public_health", False)),
        password=password or "leobons4254",
        session_secret=session_secret or hashlib.sha256(f"{host_value}:{port_value}:{password or 'leobons4254'}".encode("utf-8")).hexdigest(),
        session_timeout_minutes=max(5, int(payload.get("session_timeout_minutes", 240))),
        read_only=bool(payload.get("read_only", True)),
        allowed_ips=allowed_ips,
        mobile_refresh_seconds=max(3, int(payload.get("mobile_refresh_seconds", 8))),
        desktop_refresh_seconds=max(2, int(payload.get("desktop_refresh_seconds", 5))),
    )


def _build_execution_startup_policy(config: dict[str, Any] | None = None) -> ExecutionStartupPolicy:
    payload = config if isinstance(config, dict) else {}
    startup_revalidate_raw = payload.get("startup_revalidate", payload.get("safe_startup_revalidate", True))
    return ExecutionStartupPolicy(
        startup_revalidate=bool(startup_revalidate_raw),
        startup_ttl_seconds=max(30, int(payload.get("startup_ttl_seconds", 120))),
        startup_warmup_seconds=max(0, int(payload.get("startup_warmup_seconds", 600))),
    )


def _apply_risk_config_policy_overrides(
    policy: OrchestratorPolicy,
    *,
    risk_payload: dict[str, Any] | None,
    xau_grid_payload: dict[str, Any] | None,
) -> None:
    risk_values = risk_payload if isinstance(risk_payload, dict) else {}
    xau_values = xau_grid_payload if isinstance(xau_grid_payload, dict) else {}
    policy.daily_caution_threshold_pct = clamp(
        float(risk_values.get("daily_caution_threshold_pct", risk_values.get("soft_daily_dd_pct", policy.daily_caution_threshold_pct))),
        0.0,
        0.20,
    )
    policy.daily_defensive_threshold_pct = clamp(
        float(risk_values.get("daily_defensive_threshold_pct", risk_values.get("soft_daily_dd_pct", policy.daily_defensive_threshold_pct))),
        0.0,
        0.25,
    )
    policy.daily_hard_stop_threshold_pct = clamp(
        float(risk_values.get("daily_hard_stop_threshold_pct", risk_values.get("hard_daily_dd_pct", policy.daily_hard_stop_threshold_pct))),
        0.0,
        0.30,
    )
    policy.daily_normal_quality_floor = clamp(
        float(risk_values.get("daily_normal_quality_floor", risk_values.get("trade_quality_floor", policy.daily_normal_quality_floor))),
        0.0,
        1.0,
    )
    policy.daily_caution_quality_floor = clamp(
        float(risk_values.get("daily_caution_quality_floor", policy.daily_caution_quality_floor)),
        0.0,
        1.0,
    )
    policy.daily_defensive_quality_floor = clamp(
        float(risk_values.get("daily_defensive_quality_floor", policy.daily_defensive_quality_floor)),
        0.0,
        1.0,
    )
    policy.daily_normal_risk_multiplier = clamp(
        float(risk_values.get("daily_normal_risk_multiplier", policy.daily_normal_risk_multiplier)),
        0.0,
        2.0,
    )
    policy.daily_caution_risk_multiplier = clamp(
        float(risk_values.get("daily_caution_risk_multiplier", policy.daily_caution_risk_multiplier)),
        0.0,
        2.0,
    )
    policy.daily_defensive_risk_multiplier = clamp(
        float(risk_values.get("daily_defensive_risk_multiplier", policy.daily_defensive_risk_multiplier)),
        0.0,
        2.0,
    )
    policy.daily_hard_stop_risk_multiplier = clamp(
        float(risk_values.get("daily_hard_stop_risk_multiplier", policy.daily_hard_stop_risk_multiplier)),
        0.0,
        1.0,
    )
    policy.xau_grid_sub_budget_pct = clamp(float(xau_values.get("sub_budget_pct", policy.xau_grid_sub_budget_pct)), 0.0, 1.0)
    policy.xau_grid_caution_cycle_quality = clamp(float(xau_values.get("caution_cycle_quality", policy.xau_grid_caution_cycle_quality)), 0.0, 1.0)
    policy.xau_grid_defensive_cycle_quality = clamp(float(xau_values.get("defensive_cycle_quality", policy.xau_grid_defensive_cycle_quality)), 0.0, 1.0)
    policy.xau_grid_caution_risk_multiplier = clamp(float(xau_values.get("caution_risk_multiplier", policy.xau_grid_caution_risk_multiplier)), 0.0, 2.0)
    policy.xau_grid_defensive_risk_multiplier = clamp(float(xau_values.get("defensive_risk_multiplier", policy.xau_grid_defensive_risk_multiplier)), 0.0, 2.0)


def _effective_bridge_drawdown_guard_pct(policy: OrchestratorPolicy, current_equity: float | None) -> float:
    base_guard = abs(float(policy.max_daily_dd_pct))
    if current_equity is None:
        return base_guard
    if float(current_equity) <= max(0.0, float(policy.bootstrap_equity_threshold)):
        return max(base_guard, abs(float(policy.bootstrap_drawdown_guard_pct)))
    return base_guard


def _delivery_exec_budget_usd(
    *,
    current_equity: float,
    effective_risk_pct: float,
    policy: OrchestratorPolicy,
    validation_snapshot: dict[str, Any] | None,
    approved_risk_cap_usd: float = 0.0,
    is_canary_candidate: bool,
    is_force_test_trade: bool,
) -> float:
    if is_canary_candidate or is_force_test_trade:
        budget_usd = clamp(
            float(current_equity) * float(policy.base_risk_pct),
            float(policy.min_budget_usd),
            float(policy.max_budget_usd),
        )
    else:
        budget_usd = clamp(
            float(current_equity) * float(effective_risk_pct),
            float(policy.min_budget_usd),
            float(policy.max_budget_usd),
        )
    snapshot = validation_snapshot if isinstance(validation_snapshot, dict) else {}
    approved_risk_cap = _safe_float(snapshot.get("approved_risk_cap_usd"), 0.0)
    approved_risk_cap = max(approved_risk_cap, _safe_float(approved_risk_cap_usd, 0.0))
    if approved_risk_cap > 0:
        budget_usd = max(
            float(budget_usd),
            clamp(float(approved_risk_cap), float(policy.min_budget_usd), float(policy.max_budget_usd)),
        )
    return float(budget_usd)


def _recent_strategy_edge_snapshot(recent_strategy_trades: list[dict[str, Any]] | None) -> dict[str, Any]:
    trades = list(recent_strategy_trades or [])
    sample_count = len(trades)
    if sample_count <= 0:
        return {
            "sample_count": 0,
            "win_rate": 0.0,
            "expectancy_r": 0.0,
            "profit_factor": 1.0,
            "pnl_amount_total": 0.0,
            "performance_score": 0.50,
            "hot": False,
            "degraded": False,
            "extremely_degraded": False,
            "latest_closed_at": "",
        }

    pnl_r_values = [_safe_float(item.get("pnl_r"), 0.0) for item in trades]
    pnl_amounts = [_safe_float(item.get("pnl_amount"), _safe_float(item.get("pnl_money"), 0.0)) for item in trades]
    latest_closed_at = str(trades[0].get("closed_at") or "")
    wins = sum(1 for pnl in pnl_amounts if pnl > 0.0)
    win_rate = float(wins / max(sample_count, 1))
    expectancy_r = float(sum(pnl_r_values) / max(sample_count, 1))
    gross_profit = float(sum(max(0.0, pnl) for pnl in pnl_amounts))
    gross_loss = float(sum(abs(min(0.0, pnl)) for pnl in pnl_amounts))
    profit_factor = (
        float(gross_profit / gross_loss)
        if gross_loss > 1e-9
        else (float(gross_profit) if gross_profit > 0.0 else 1.0)
    )
    total_pnl_amount = float(sum(pnl_amounts))
    pf_score = clamp((profit_factor - 0.65) / 0.85, 0.0, 1.0)
    expectancy_score = clamp((expectancy_r + 0.10) / 0.24, 0.0, 1.0)
    performance_score = clamp((win_rate * 0.40) + (pf_score * 0.34) + (expectancy_score * 0.26), 0.0, 1.0)
    hot = bool(
        sample_count >= 4
        and win_rate >= 0.62
        and expectancy_r >= 0.03
        and profit_factor >= 1.08
        and total_pnl_amount > 0.0
    )
    degraded = bool(
        sample_count >= 4
        and (
            win_rate <= 0.40
            or expectancy_r <= -0.03
            or (profit_factor <= 0.92 and total_pnl_amount < 0.0)
        )
    )
    extremely_degraded = bool(
        sample_count >= 4
        and (
            win_rate <= 0.25
            or expectancy_r <= -0.10
            or (profit_factor <= 0.72 and total_pnl_amount < 0.0)
        )
    )
    return {
        "sample_count": int(sample_count),
        "win_rate": float(win_rate),
        "expectancy_r": float(expectancy_r),
        "profit_factor": float(profit_factor),
        "pnl_amount_total": float(total_pnl_amount),
        "performance_score": float(performance_score),
        "hot": bool(hot),
        "degraded": bool(degraded),
        "extremely_degraded": bool(extremely_degraded),
        "latest_closed_at": latest_closed_at,
    }


def _targeted_live_loss_bucket_block_reason(
    *,
    symbol_key: str,
    setup: str,
    strategy_state: str,
) -> tuple[str | None, dict[str, Any]]:
    state_key = str(strategy_state or "").upper()
    setup_key = str(setup or "").upper()
    is_grid_setup = "GRID" in setup_key
    if not state_key:
        return None, {}
    if symbol_key == "XAUUSD" and is_grid_setup and state_key in {"QUARANTINED", "REDUCED"}:
        return (
            "xau_grid_degraded_live_block",
            {
                "targeted_live_block": True,
                "targeted_live_block_symbol": symbol_key,
                "targeted_live_block_setup": setup_key,
                "targeted_live_block_strategy_state": state_key,
            },
        )
    if symbol_key in {"AUDJPY", "NZDJPY", "AUDNZD"} and "BREAKOUT" in setup_key and state_key in {"QUARANTINED", "REDUCED"}:
        return (
            "breakout_quarantined_live_block",
            {
                "targeted_live_block": True,
                "targeted_live_block_symbol": symbol_key,
                "targeted_live_block_setup": setup_key,
                "targeted_live_block_strategy_state": state_key,
            },
        )
    return None, {}


def create_bridge_app(
    queue: BridgeActionQueue,
    journal: TradeJournal,
    online_learning: OnlineLearningEngine,
    learning_brain: ApexLearningBrain | None = None,
    session_name_resolver=default_session_name,
    ai_gate: Any | None = None,
    logger: ApexLogger | None = None,
    auth_token: str = "",
    orchestrator_config: dict[str, Any] | None = None,
    risk_config: dict[str, Any] | None = None,
    execution_config: dict[str, Any] | None = None,
    xau_grid_config: dict[str, Any] | None = None,
    dashboard_config: dict[str, Any] | None = None,
    symbol_rules_path: Path | None = None,
    market_data_status_provider: Any | None = None,
    runtime_metrics_provider: Any | None = None,
    strategy_optimizer: StrategyOptimizer | None = None,
    telegram_config: dict[str, Any] | None = None,
):
    global _SHARED_OPERATOR_CONTROL_STATE, _SHARED_STARTUP_RUNTIME_STATE
    from fastapi import FastAPI, Header, HTTPException, Request
    from fastapi.responses import HTMLResponse, JSONResponse, RedirectResponse

    token = auth_token.strip()
    policy = _build_policy(orchestrator_config)
    dashboard_policy = _build_dashboard_policy(
        dashboard_config,
        default_host="127.0.0.1",
        default_port=8000,
    )
    telegram_policy = telegram_config_from_mapping(telegram_config if isinstance(telegram_config, dict) else {})
    execution_policy = _build_execution_startup_policy(execution_config)
    risk_payload = risk_config if isinstance(risk_config, dict) else {}
    xau_grid_payload = xau_grid_config if isinstance(xau_grid_config, dict) else {}
    _apply_risk_config_policy_overrides(
        policy,
        risk_payload=risk_payload,
        xau_grid_payload=xau_grid_payload,
    )
    rule_change_payload = {}
    if isinstance(orchestrator_config, dict):
        raw_rule_change = orchestrator_config.get("rule_change", {})
        if isinstance(raw_rule_change, dict):
            rule_change_payload = raw_rule_change
    rule_change_manager = RuleChangeManager(
        db_path=queue.db_path,
        config=RuleChangeConfig(
            enabled=bool(rule_change_payload.get("enabled", False)),
            min_samples=max(1, int(rule_change_payload.get("min_samples", 50))),
            min_grid_cycles=max(1, int(rule_change_payload.get("min_grid_cycles", 10))),
            cooldown_hours=max(1, int(rule_change_payload.get("cooldown_hours", 24))),
            shadow_trades_required=max(1, int(rule_change_payload.get("shadow_trades_required", 25))),
            max_delta_pct=float(rule_change_payload.get("max_delta_pct", 0.20)),
            min_profit_factor_gain=float(rule_change_payload.get("min_profit_factor_gain", 0.05)),
            min_expectancy_gain=float(rule_change_payload.get("min_expectancy_gain", 0.02)),
            allowed_params=tuple(str(item) for item in rule_change_payload.get("allowed_params", []) if str(item).strip())
            or RuleChangeConfig.allowed_params,
            locked_params=tuple(str(item) for item in rule_change_payload.get("locked_params", []) if str(item).strip())
            or RuleChangeConfig.locked_params,
        ),
        logger=logger,
    )
    if strategy_optimizer is None:
        strategy_optimizer_payload = {}
        if isinstance(orchestrator_config, dict):
            raw_optimizer = orchestrator_config.get("strategy_optimizer", {})
            if isinstance(raw_optimizer, dict):
                strategy_optimizer_payload = raw_optimizer
        strategy_optimizer = StrategyOptimizer(
            trade_history_path=Path(str(strategy_optimizer_payload.get("trade_history_path") or (queue.db_path.parent / "trade_history.json"))),
            metrics_path=Path(str(strategy_optimizer_payload.get("metrics_path") or (queue.db_path.parent / "strategy_metrics.json"))),
            enabled=bool(strategy_optimizer_payload.get("enabled", True)),
            min_trades_per_strategy=max(5, int(strategy_optimizer_payload.get("min_trades_per_strategy", 50))),
            lookback_days=max(7, int(strategy_optimizer_payload.get("lookback_days", 90))),
            low_win_rate_threshold=clamp(float(strategy_optimizer_payload.get("low_win_rate_threshold", 0.45)), 0.1, 0.9),
            high_win_rate_threshold=clamp(float(strategy_optimizer_payload.get("high_win_rate_threshold", 0.60)), 0.1, 0.95),
            adjustment_step_pct=clamp(float(strategy_optimizer_payload.get("adjustment_step_pct", 0.10)), 0.01, 0.20),
            min_adjustment_multiplier=clamp(float(strategy_optimizer_payload.get("min_adjustment_multiplier", 0.75)), 0.50, 1.0),
            max_adjustment_multiplier=clamp(float(strategy_optimizer_payload.get("max_adjustment_multiplier", 1.25)), 1.0, 2.0),
            cooldown_minutes=max(1, int(strategy_optimizer_payload.get("cooldown_minutes", 30))),
            logger=logger,
        )
        strategy_optimizer.register_strategies(
            [
                "XAUUSD_M5_GRID",
                "XAUUSD_M1_MICRO",
                "XAUUSD_M15_STRUCTURED",
                "XAUUSD_NON_GRID",
                "EURUSD_LONDON_BREAKOUT",
                "GBPUSD_BREAKER_BLOCK",
                "USDJPY_SESSION_SCALP",
                "BTC_TREND_SCALP",
                "BTC_WEEKEND_CANARY",
                "NAS_SESSION_SCALPER",
                "OIL_INVENTORY_SCALPER",
                "FORCE_TEST_TRADE",
            ]
        )
    globals()["rule_change_manager"] = rule_change_manager
    globals()["strategy_optimizer"] = strategy_optimizer
    symbol_auto_discovery_payload = {}
    if isinstance(orchestrator_config, dict):
        raw_discovery = orchestrator_config.get("symbol_auto_discovery", {})
        if isinstance(raw_discovery, dict):
            symbol_auto_discovery_payload = raw_discovery
    unknown_training_min_samples = max(1, int(symbol_auto_discovery_payload.get("min_samples", 120)))
    unknown_training_max_spread_points = max(1.0, float(symbol_auto_discovery_payload.get("max_spread_points", policy.max_spread_points_other)))
    unknown_training_backtest_pass_score = clamp(float(symbol_auto_discovery_payload.get("min_pass_score", 0.55)), 0.0, 1.0)
    if "min_observation_days" in symbol_auto_discovery_payload:
        unknown_training_min_observation_days = max(0, int(symbol_auto_discovery_payload.get("min_observation_days", policy.symbol_auto_discovery_min_observation_days)))
    elif unknown_training_min_samples <= 2:
        unknown_training_min_observation_days = 0
    else:
        unknown_training_min_observation_days = max(1, int(policy.symbol_auto_discovery_min_observation_days))
    resolved_rules_path = symbol_rules_path or (Path(__file__).resolve().parents[1] / "config" / "symbol_rules.yaml")
    symbol_rules = load_symbol_rules(resolved_rules_path)
    pull_log_state: dict[str, tuple[str, datetime]] = {}
    governor_state: dict[str, dict[str, Any]] = {}
    news_mode_log_state: dict[str, str] = {}
    ai_entry_cache: dict[str, tuple[datetime, dict[str, Any], str]] = {}
