    def _pair_day_scoreboard(
        *,
        account: str | None,
        magic: int | None,
    ) -> dict[str, Any]:
        current_day_key = current_trading_day_key()
        grouped: dict[str, dict[str, Any]] = {}
        for trade in journal.closed_trades(250, account=account, magic=magic):
            symbol_key = _normalize_symbol_key(str(trade.get("symbol") or ""))
            if not symbol_key:
                continue
            bucket = grouped.setdefault(
                symbol_key,
                {
                    "symbol": symbol_key,
                    "today_pnl": 0.0,
                    "today_trades": 0,
                    "rolling_expectancy_by_pair": 0.0,
                    "rolling_pf_by_pair": 1.0,
                    "rolling_wins": 0,
                    "rolling_losses": 0,
                    "rolling_samples": 0,
                },
            )
            pnl_amount = float(trade.get("pnl_amount") or 0.0)
            pnl_r = float(trade.get("pnl_r") or 0.0)
            bucket["rolling_expectancy_by_pair"] += pnl_r
            bucket["rolling_samples"] += 1
            if pnl_amount >= 0.0:
                bucket["rolling_wins"] += 1
            else:
                bucket["rolling_losses"] += 1
            if trading_day_key_for_timestamp(trade.get("closed_at")) == current_day_key:
                bucket["today_pnl"] += pnl_amount
                bucket["today_trades"] += 1
        results: list[dict[str, Any]] = []
        for item in grouped.values():
            samples = max(1, int(item["rolling_samples"]))
            wins = int(item["rolling_wins"])
            losses = int(item["rolling_losses"])
            symbol_trades = journal.closed_trades(50, symbol=item["symbol"], account=account, magic=magic)
            profit_total = sum(max(0.0, float(row.get("pnl_amount") or 0.0)) for row in symbol_trades)
            loss_total = sum(abs(min(0.0, float(row.get("pnl_amount") or 0.0))) for row in symbol_trades)
            item["rolling_expectancy_by_pair"] = float(item["rolling_expectancy_by_pair"]) / samples
            item["rolling_pf_by_pair"] = float(profit_total / loss_total) if loss_total > 0 else (profit_total if profit_total > 0 else 1.0)
            item["rolling_win_rate_by_pair"] = float(wins / max(1, wins + losses))
            results.append(item)
        top_earning = sorted(results, key=lambda row: (float(row["today_pnl"]), int(row["today_trades"])), reverse=True)[:5]
        top_losing = sorted(results, key=lambda row: (float(row["today_pnl"]), -int(row["today_trades"])))[:5]
        return {
            "top_earning_pairs_today": top_earning,
            "top_losing_pairs_today": top_losing,
        }

