                expected_value_r = float(runtime.get("last_candidate_expected_value_r") or 0.0)
                approved = bool(debug_payload.get("execution_state", {}).get("pre_exec_pass")) and not blocker
                near_tradable = bool(candidate_attempts > 0 and quality_score >= 0.55 and str(debug_payload.get("market_open_status") or "").upper() in {"OPEN", "OPEN_24_7", "PRE_OPEN"})
                selected_band = str(runtime.get("selected_trade_band") or quality_band or "")
                if selected_band in band_counts:
                    band_counts[selected_band] += 1
                primary_block_reason = blocker
