    @app.post("/dashboard/control/reset_daily_guard")
    def dashboard_reset_daily_guard(request: StarletteRequest) -> JSONResponse:
        _dashboard_require_auth(request)
        active_account, active_magic, active_snapshot = _select_active_bridge_context()
        current_equity = _fallback_equity((active_snapshot or {}).get("equity") if isinstance(active_snapshot, dict) else None)
        if active_account and active_magic:
            journal.reset_daily_guard(account=str(active_account), magic=int(active_magic), current_equity=current_equity)
        _record_dashboard_event(
            "operator_reset_daily_guard",
            reason="operator_reset_daily_guard",
            extra={"account": str(active_account or ""), "magic": int(active_magic or 0)},
        )
        _log(
            logger,
            "warning",
            "operator_reset_daily_guard",
            account=str(active_account or ""),
            magic=int(active_magic or 0),
            current_equity=float(current_equity or 0.0),
        )
        return _dashboard_control_response(action="reset_daily_guard", reason="operator_reset_daily_guard")

