    @app.post("/dashboard/control/clear_startup_warmup")
    def dashboard_clear_startup_warmup(request: StarletteRequest) -> JSONResponse:
        _dashboard_require_auth(request)
        now_ts = utc_now()
        startup_runtime_state["entries_blocked_until"] = _to_iso(now_ts)
        startup_runtime_state["warmup_finished_logged"] = False
        _warmup_active(now_ts)
        _record_dashboard_event("operator_clear_startup_warmup", reason="operator_clear_startup_warmup")
        _log(logger, "warning", "operator_clear_startup_warmup", cleared_at=_to_iso(now_ts))
        return _dashboard_control_response(action="clear_startup_warmup", reason="operator_clear_startup_warmup")

    @app.get("/telegram/status")
    def telegram_status(request: StarletteRequest) -> JSONResponse:
        if bool(dashboard_policy.enabled):
            _dashboard_require_auth(request)
        else:
            _require_local_internal_access(request)
        _purge_expired_telegram_commands()
        owner_configured = bool(os.getenv(str(telegram_policy.owner_chat_id_env), "").strip())
        token_configured = bool(os.getenv(str(telegram_policy.token_env), "").strip())
        webhook_secret_configured = bool(_telegram_secret_value())
        payload = {
            "enabled": bool(telegram_policy.enabled),
            "bot_username": str(telegram_policy.bot_username),
            "token_configured": token_configured,
            "owner_chat_id_configured": owner_configured,
            "webhook_secret_configured": webhook_secret_configured,
            "ai_enabled": bool(telegram_policy.ai_enabled),
            "allow_controls": bool(telegram_policy.allow_controls),
            "confirmation_ttl_seconds": _telegram_confirmation_ttl_seconds(),
            "pending_commands": len(telegram_pending_commands),
        }
        return JSONResponse(_json_safe(payload))

    @app.post("/telegram/webhook")
    async def telegram_webhook(request: StarletteRequest) -> JSONResponse:
        if not bool(telegram_policy.enabled):
            return JSONResponse({"ok": False, "reason": "telegram_disabled"}, status_code=200)
        expected_secret = _telegram_secret_value()
        provided_secret = str(request.headers.get("x-telegram-bot-api-secret-token") or "").strip()
        if expected_secret:
            if not hmac.compare_digest(provided_secret, expected_secret):
                raise HTTPException(status_code=403, detail="telegram_secret_invalid")
        elif not _request_is_local(request):
            raise HTTPException(status_code=403, detail="telegram_secret_required")
        try:
            update = await request.json()
        except Exception as exc:
            raise HTTPException(status_code=400, detail="invalid_telegram_payload") from exc
        if not isinstance(update, dict):
            raise HTTPException(status_code=400, detail="invalid_telegram_payload")
        message = extract_telegram_message(update)
        if message is None:
            return JSONResponse({"ok": True, "handled": False, "reason": "no_message"})
        try:
            client = telegram_client_from_env(telegram_policy)
        except ApexTelegramError as exc:
            _log(logger, "error", "telegram_client_unavailable", error=str(exc))
            return JSONResponse({"ok": False, "handled": False, "reason": str(exc)}, status_code=200)
        _purge_expired_telegram_commands()
        owner_chat_id = owner_chat_id_from_env(telegram_policy, None)
        owner_authorized = bool(owner_chat_id) and hmac.compare_digest(str(message.chat_id), str(owner_chat_id))
        controls_allowed = bool(telegram_policy.allow_controls and owner_authorized and owner_chat_id)
        responder_policy = replace(telegram_policy, allow_controls=controls_allowed)
        responder = ApexTelegramResponder(config=responder_policy, ai_explainer=_telegram_openai_explain)
        dashboard_payload = _dashboard_data_payload()
        result = responder.handle_update(update, dashboard_payload)
        reply_text = str(result.text or "")
        action_result: dict[str, Any] = {}
        if not owner_authorized:
            reply_text = (
                "This bot is locked until TELEGRAM_CHAT_ID is configured."
                if not owner_chat_id
                else "This bot is locked to the configured owner chat."
            )
        elif result.confirm_command_id:
            command_id = str(result.confirm_command_id)
            pending = telegram_pending_commands.get(command_id)
            if not pending:
                reply_text = f"No pending command found for <code>{_urlquote(command_id)}</code>."
            elif str(pending.get("chat_id") or "") != str(message.chat_id):
                reply_text = "That pending command belongs to a different chat."
            elif (expires_at := _coerce_iso_datetime(str(pending.get("expires_at") or ""))) is not None and expires_at <= utc_now():
                telegram_pending_commands.pop(command_id, None)
                reply_text = f"Pending command <code>{_urlquote(command_id)}</code> expired. Send the command again."
            else:
                action_result = _telegram_control_execute(str(pending.get("action") or ""), source="telegram_confirmed")
                telegram_pending_commands.pop(command_id, None)
                reply_text = (
                    f"Executed <code>{str(action_result.get('action') or pending.get('action') or '')}</code>.\n"
                    f"Result: <code>{'ok' if bool(action_result.get('ok')) else str(action_result.get('reason') or 'not_ok')}</code>"
                )
        elif result.confirmation_required and result.action:
            expires_at = utc_now() + timedelta(seconds=_telegram_confirmation_ttl_seconds())
            telegram_pending_commands[str(result.command_id)] = {
                "action": str(result.action),
                "chat_id": str(message.chat_id),
                "user_id": str(message.user_id),
                "requested_at": _iso_now(),
                "expires_at": _to_iso(expires_at),
            }
        elif result.action:
            action_result = _telegram_control_execute(str(result.action), source="telegram")
            reply_text = (
                f"Executed <code>{str(action_result.get('action') or result.action)}</code>.\n"
                f"Result: <code>{'ok' if bool(action_result.get('ok')) else str(action_result.get('reason') or 'not_ok')}</code>"
            )
        if reply_text:
            try:
                client.send_message(message.chat_id, reply_text, parse_mode=str(telegram_policy.parse_mode))
            except ApexTelegramError as exc:
                _log(logger, "error", "telegram_send_failed", error=str(exc))
                return JSONResponse({"ok": False, "handled": True, "reason": str(exc)}, status_code=200)
        _record_dashboard_event(
            "telegram_message",
            reason=str(message.text)[:180],
            extra={
                "chat_id": str(message.chat_id),
                "user_id": str(message.user_id),
                "action": str(result.action or action_result.get("action") or ""),
                "confirmation_required": bool(result.confirmation_required),
            },
        )
        return JSONResponse(
            _json_safe(
                {
                    "ok": True,
                    "handled": bool(result.handled),
                    "chat_id": str(message.chat_id),
                    "action": str(result.action or action_result.get("action") or ""),
                    "confirmation_required": bool(result.confirmation_required),
                    "pending_commands": len(telegram_pending_commands),
                    "sent": bool(reply_text),
                }
            )
        )

    @app.post("/v1/mt5_snapshot")
    def mt5_snapshot(request: StarletteRequest, payload: dict[str, Any], x_bridge_token: Optional[str] = Header(default=None)) -> dict[str, Any]:
        _require_local_internal_access(request)
        _check_auth(x_bridge_token)
        symbol = str(payload.get("symbol") or "").strip()
        account = str(payload.get("account") or "").strip()
        if not symbol or not account:
            raise HTTPException(status_code=400, detail="symbol and account required")
        magic = int(payload.get("magic") or 0)
        timeframe_value = str(payload.get("timeframe") or payload.get("tf") or "M5").upper()
        symbol_key = _normalize_symbol_key(symbol)
        snapshot_key = f"{account}:{magic}:{symbol_key}"
        data = {
            "bid": _safe_float(payload.get("bid"), 0.0),
            "ask": _safe_float(payload.get("ask"), 0.0),
            "last_price": _safe_float(payload.get("last"), 0.0),
            "spread_points": _safe_float(payload.get("spread_points"), 0.0),
            "open_count": payload.get("open_count"),
            "net_lots": payload.get("net_lots"),
            "avg_entry": payload.get("avg_entry"),
            "floating_pnl": payload.get("floating_pnl"),
            "positions": payload.get("positions", []),
            "updated_at": _iso_now(),
            "source": "mt5_snapshot",
        }
        mt5_snapshot_state[snapshot_key] = data
        queue.update_account_snapshot(
            account=account,
            symbol=symbol,
            magic=magic,
            balance=payload.get("balance"),
            equity=payload.get("equity"),
            free_margin=payload.get("free_margin"),
        )
        state = queue.sync_reality_from_pull(
            account=account,
            magic=magic,
            symbol_key=symbol_key,
            timeframe=timeframe_value,
            open_count=payload.get("open_count"),
            net_lots=payload.get("net_lots"),
            avg_entry=payload.get("avg_entry"),
            floating_pnl=payload.get("floating_pnl"),
            stale_seconds=int(policy.reality_sync_stale_seconds),
            low_confidence_after_seconds=int(policy.reality_low_confidence_after_seconds),
            drift_open_count_threshold=int(policy.reality_drift_open_count_threshold),
        )
        _runtime_update(
            symbol_key,
            {
                "snapshot_available": True,
                "snapshot_missing": False,
                "snapshot_age_seconds": 0.0,
                "last_snapshot_at": _iso_now(),
            },
        )
        return {
            "ok": True,
            "symbol": symbol_key,
            "account": account,
            "magic": magic,
            "state_confidence": str(state.get("state_confidence") or "medium"),
            "reality_source": str(state.get("reality_source") or "pull_params"),
        }

    @app.get("/v1/pull")
    def pull(
        request: StarletteRequest,
        symbol: str,
        account: str,
        magic: int,
        timeframe: Optional[str] = None,
        tf: Optional[str] = None,
        balance: Optional[float] = None,
        equity: Optional[float] = None,
        free_margin: Optional[float] = None,
        margin: Optional[float] = None,
        margin_level: Optional[float] = None,
        leverage: Optional[int] = None,
        spread_points: Optional[float] = None,
        bid: Optional[float] = None,
        ask: Optional[float] = None,
        last: Optional[float] = None,
        point: Optional[float] = None,
        digits: Optional[int] = None,
        tick_size: Optional[float] = None,
        tick_value: Optional[float] = None,
        lot_min: Optional[float] = None,
        lot_max: Optional[float] = None,
        lot_step: Optional[float] = None,
        contract_size: Optional[float] = None,
        stops_level: Optional[int] = None,
        freeze_level: Optional[int] = None,
        open_count: Optional[int] = None,
        net_lots: Optional[float] = None,
        avg_entry: Optional[float] = None,
        floating_pnl: Optional[float] = None,
        total_open_positions: Optional[int] = None,
        gross_lots_total: Optional[float] = None,
        net_lots_total: Optional[float] = None,
        floating_pnl_total: Optional[float] = None,
        symbol_selected: Optional[int] = None,
        symbol_trade_mode: Optional[int] = None,
        terminal_connected: Optional[int] = None,
        terminal_trade_allowed: Optional[int] = None,
        mql_trade_allowed: Optional[int] = None,
        server_time: Optional[int] = None,
        gmt_time: Optional[int] = None,
        x_bridge_token: Optional[str] = Header(default=None),
    ) -> dict[str, Any]:
        _require_local_internal_access(request)
        _check_auth(x_bridge_token)
        queue.update_account_snapshot(
            account=account,
            symbol=symbol,
            magic=magic,
            balance=balance,
            equity=equity,
            free_margin=free_margin,
            extras={
                "margin": margin,
                "margin_level": margin_level,
                "leverage": leverage,
                "spread_points": spread_points,
                "bid": bid,
                "ask": ask,
                "last": last,
                "point": point,
                "digits": digits,
                "tick_size": tick_size,
                "tick_value": tick_value,
                "lot_min": lot_min,
                "lot_max": lot_max,
                "lot_step": lot_step,
                "contract_size": contract_size,
                "stops_level": stops_level,
                "freeze_level": freeze_level,
                "open_count": open_count,
                "net_lots": net_lots,
                "avg_entry": avg_entry,
                "floating_pnl": floating_pnl,
                "total_open_positions": total_open_positions,
                "gross_lots_total": gross_lots_total,
                "net_lots_total": net_lots_total,
                "floating_pnl_total": floating_pnl_total,
                "symbol_selected": symbol_selected,
                "symbol_trade_mode": symbol_trade_mode,
                "terminal_connected": terminal_connected,
                "terminal_trade_allowed": terminal_trade_allowed,
                "mql_trade_allowed": mql_trade_allowed,
                "server_time": server_time,
                "gmt_time": gmt_time,
            },
        )
        queue.cancel_stale_delivered(
            max_age_seconds=max(
                20,
                int(policy.open_lock_seconds) + max(5, int(policy.delivery_timeout_requeue_grace_seconds)),
            ),
            retry_limit=int(policy.delivery_timeout_retry_limit),
            requeue_grace_seconds=int(policy.delivery_timeout_requeue_grace_seconds),
        )
        queue.cleanup_expired_locks()
        symbol_key = _normalize_symbol_key(symbol)
        timeframe_value = str(timeframe or tf or "M5").upper()
        timeframe_route = _resolve_timeframe_route(symbol_key, timeframe_value)
        account_id = str(account).strip()
        now = utc_now()
        session_name = _session_name_utc(now)
        schedule_state = describe_market_state(symbol_key, now)
        base_market_open, base_market_status = bool(schedule_state.market_open), str(schedule_state.market_open_status)
        _maybe_run_runtime_maintenance(now, session_name, account=account_id, magic=int(magic))
        account_snapshot = queue.get_account_snapshot(account=account_id, symbol=symbol_key, magic=int(magic)) or {}
        current_equity = float(account_snapshot.get("equity") or equity or balance or internal_equity_estimate)
        snapshot_key = f"{account_id}:{int(magic)}:{symbol_key}"
        snapshot = mt5_snapshot_state.get(snapshot_key, {})
        snapshot_updated_at = snapshot.get("updated_at")
        snapshot_age_seconds = None
        if isinstance(snapshot_updated_at, str) and snapshot_updated_at:
            try:
                snapshot_age_seconds = max(0.0, (now - _parse_iso(snapshot_updated_at)).total_seconds())
            except Exception:
                snapshot_age_seconds = None
        if snapshot and snapshot_age_seconds is not None and snapshot_age_seconds > float(policy.reality_sync_stale_seconds):
            snapshot = {}
        pull_open_count = open_count if open_count is not None else snapshot.get("open_count")
        pull_net_lots = net_lots if net_lots is not None else snapshot.get("net_lots")
        pull_avg_entry = avg_entry if avg_entry is not None else snapshot.get("avg_entry")
        pull_floating_pnl = floating_pnl if floating_pnl is not None else snapshot.get("floating_pnl")
        effective_spread_points = float(spread_points) if spread_points is not None else 0.0
        symbol_rule: SymbolRule = _symbol_rule_with_snapshot_overrides(
            resolve_symbol_rule(symbol, symbol_rules),
            account_snapshot,
        )
        if effective_spread_points <= 0:
            effective_spread_points = float(symbol_rule.typical_spread_points)
        entry_hint = float(last or 0.0)
        if entry_hint <= 0 and bid is not None and ask is not None and float(bid) > 0 and float(ask) > 0:
            entry_hint = (float(bid) + float(ask)) * 0.5
        if entry_hint <= 0 and snapshot:
            entry_hint = float(snapshot.get("last_price") or 0.0)
        quote_truth = _update_market_quote_state(
            symbol_key=symbol_key,
            price=float(entry_hint),
            spread_points=float(effective_spread_points),
            point_size=max(float(symbol_rule.point), 1e-6),
            now_ts=now,
        )
        market_open, market_status = _market_quote_override(
            symbol_key=symbol_key,
            base_market_open=base_market_open,
            base_market_status=base_market_status,
            quote_state=quote_truth,
            now_ts=now,
        )
        xau_eligible_session = session_name in set(policy.xau_grid_allowed_sessions)
        if market_open:
            _record_activity(symbol_key, "scans", now)
            market_closed_log_state.pop(symbol_key, None)
            if symbol_key == "XAUUSD":
                if xau_eligible_session:
                    xau_grid_session_log_state.pop(symbol_key, None)
                    _log(
                        logger,
                        "info",
                        "XAU_GRID_SCAN",
                        symbol="XAUUSD",
                        session=session_name,
                        spread=float(effective_spread_points),
                        timeframe=timeframe_value,
                    )
                else:
                    _record_activity(symbol_key, "session_ineligible_rejects", now)
                    previous_xau_grid_state = xau_grid_session_log_state.get(symbol_key)
                    block_state = f"{session_name}:grid_session_block"
                    if previous_xau_grid_state != block_state:
                        _log(
                            logger,
                            "info",
                            "XAU_GRID_BLOCKED",
                            symbol="XAUUSD",
                            reason="grid_session_block",
                            session=session_name,
                            allowed_sessions=list(policy.xau_grid_allowed_sessions),
                            timeframe=timeframe_value,
                        )
                        xau_grid_session_log_state[symbol_key] = block_state
        else:
            _record_activity(symbol_key, "market_closed_blocks", now)
            previous_market_status = market_closed_log_state.get(symbol_key)
            if previous_market_status != market_status:
                _log(logger, "info", "MARKET_CLOSED_BLOCK", symbol=symbol_key, status=market_status, session=session_name)
                market_closed_log_state[symbol_key] = market_status
        _runtime_update(
            symbol_key,
            {
                "last_pull_account": account_id,
                "last_pull_magic": int(magic),
                "last_pull_timeframe": timeframe_value,
                "last_session": session_name,
                "last_spread_points": float(spread_points or 0.0),
                "snapshot_available": bool(snapshot),
                "snapshot_age_seconds": snapshot_age_seconds,
                "snapshot_missing": open_count is None and not bool(snapshot),
                "eligible_session": bool(xau_eligible_session if symbol_key == "XAUUSD" else market_open),
                "market_open_status": market_status,
                "market_open": bool(market_open),
                "next_open_time_utc": schedule_state.next_open_time_utc,
                "next_open_time_local": schedule_state.next_open_time_local,
                "pre_open_window_active": bool(schedule_state.pre_open_window_active),
                "dst_mode_active": dict(schedule_state.dst_mode_active),
                "scans_last_15m": _activity_count(symbol_key, "scans", window_seconds=900),
                "market_closed_rejects_last_15m": _activity_count(symbol_key, "market_closed_blocks", window_seconds=900),
                "requested_timeframe": timeframe_route.get("requested_timeframe"),
                "execution_timeframe_used": timeframe_route.get("execution_timeframe_used"),
                "internal_timeframes_used": list(timeframe_route.get("internal_timeframes_used", [])),
                "attachment_dependency_resolved": bool(timeframe_route.get("attachment_dependency_resolved")),
                "attached_tf_fallback_used": bool(timeframe_route.get("attached_tf_fallback_used")),
                "quote_unchanged_pulls": int(quote_truth.get("unchanged_pulls", 0)),
                "quote_last_change_at": quote_truth.get("last_change_at"),
                "quote_move_30m_pct": float(quote_truth.get("move_30m_pct", 0.0) or 0.0),
            },
        )
        if not market_open:
            summary = f"NONE:blocked:market_closed:{market_status}"
            _runtime_update(
                symbol_key,
                {
                    "last_reject_stage": "market",
                    "last_reject_reason": "market_closed",
                    "last_pull_summary": summary,
                    "last_pull_actions": 0,
                    "last_pull_blocked_count": 1,
                    "last_pull_blocked_reason": "market_closed",
                    "reason_top_last_15m": _reason_top_last_window(symbol_key, minutes=15),
                },
            )
            log_key = f"{symbol_key}:{account_id}:{int(magic)}"
            log_state = pull_log_state.get(log_key)
            if log_state is None or log_state[0] != summary or (now - log_state[1]).total_seconds() >= 30:
                _log(
                    logger,
                    "info",
                    "bridge_pull_decision",
                    symbol=symbol.upper(),
                    actions=0,
                    summary=summary,
                    account=account,
                    magic=magic,
                    tf=timeframe_value,
                    blocked_count=1,
                )
                pull_log_state[log_key] = (summary, now)
            return {"actions": []}
        symbol_state = queue.sync_reality_from_pull(
            account=account_id,
            magic=int(magic),
            symbol_key=symbol_key,
            timeframe=timeframe_value,
            open_count=pull_open_count,
            net_lots=pull_net_lots,
            avg_entry=pull_avg_entry,
            floating_pnl=pull_floating_pnl,
            stale_seconds=int(policy.reality_sync_stale_seconds),
            low_confidence_after_seconds=int(policy.reality_low_confidence_after_seconds),
            drift_open_count_threshold=int(policy.reality_drift_open_count_threshold),
        )
        _maybe_enqueue_canary_candidate(
            symbol_key=symbol_key,
            symbol=symbol,
            account_id=account_id,
            magic=int(magic),
            timeframe_value=timeframe_value,
            entry_hint=entry_hint,
            spread_points=effective_spread_points,
            current_equity=current_equity,
            free_margin=float(free_margin) if free_margin is not None else _safe_float(account_snapshot.get("free_margin"), 0.0),
            account_snapshot=account_snapshot,
        )
        _maybe_enqueue_force_test_trade(
            symbol_key=symbol_key,
            symbol=symbol,
            account_id=account_id,
            magic=int(magic),
            timeframe_value=timeframe_value,
            entry_hint=entry_hint,
            spread_points=effective_spread_points,
            current_equity=current_equity,
            free_margin=float(free_margin) if free_margin is not None else _safe_float(account_snapshot.get("free_margin"), 0.0),
            account_snapshot=account_snapshot,
        )

        if not _is_known_symbol(symbol_key):
            training_state = _update_unknown_symbol_training(
                symbol_key=symbol_key,
                session_name=session_name,
                spread_points=effective_spread_points,
                entry_hint=entry_hint,
                now_ts=now,
            )
            _runtime_update(
                symbol_key,
                {
                    "last_reject_stage": "symbol_auto_discovery",
                    "last_reject_reason": "symbol_training_mode" if str(training_state.get("status", "")).upper() != "ACTIVE" else "",
                    "symbol_training_mode": dict(training_state),
                },
            )
            training_status = str(training_state.get("status", "TRAINING")).upper()
            previous_training_status = symbol_training_log_state.get(symbol_key)
            if previous_training_status is None:
                _log(
                    logger,
                    "info",
                    "symbol_discovered",
                    symbol=symbol_key,
                    strategy_template=str(training_state.get("strategy_template", "")),
                    blueprint=dict(training_state.get("strategy_blueprint", {})),
                )
            elif previous_training_status != training_status and training_status == "ACTIVE":
                _log(
                    logger,
                    "info",
                    "symbol_training_activated",
                    symbol=symbol_key,
                    sample_count=int(training_state.get("sample_count", 0)),
                    pass_score=float(training_state.get("pass_score", 0.0)),
                )
            elif int(training_state.get("sample_count", 0)) in {1, 20, 50, 100}:
                _log(
                    logger,
                    "info",
                    "symbol_training_progress",
                    symbol=symbol_key,
                    status=training_status,
                    sample_count=int(training_state.get("sample_count", 0)),
                    pass_score=float(training_state.get("pass_score", 0.0)),
                )
            symbol_training_log_state[symbol_key] = training_status
            if str(training_state.get("status", "")).upper() != "ACTIVE":
                summary = "NONE:symbol_training_mode"
                _log(
                    logger,
                    "info",
                    "bridge_pull_decision",
                    symbol=symbol.upper(),
                    actions=0,
                    summary=summary,
                    account=account,
                    magic=magic,
                    tf=timeframe_value,
                    blocked_count=1,
                )
                return {"actions": []}

        _enqueue_management_actions(
            account_id=account_id,
            magic=int(magic),
            symbol=symbol,
            symbol_key=symbol_key,
            timeframe_value=timeframe_value,
            current_price=entry_hint,
            spread_points=effective_spread_points,
        )

        fetch_limit = max(25, int(policy.max_actions_per_pull) * 8)
        fetch_timeframes: list[str] = []
        for candidate_tf in (
            timeframe_value,
            str(timeframe_route.get("execution_timeframe_used") or ""),
            *[str(item) for item in timeframe_route.get("internal_timeframes_used", [])],
        ):
            normalized_tf = str(candidate_tf or "").upper().strip()
            if normalized_tf and normalized_tf not in fetch_timeframes:
                fetch_timeframes.append(normalized_tf)
        merged: list[sqlite3.Row] = []
        seen_signal_ids: set[str] = set()
        for fetch_tf in fetch_timeframes or [timeframe_value]:
            rows = queue.fetch_candidates(
                symbol=symbol,
                timeframe=fetch_tf,
                account=account_id,
                magic=int(magic),
                include_delivered=bool(policy.allow_redelivery),
                limit=fetch_limit,
            )
            for row in rows:
                signal_id = str(row["signal_id"])
                if signal_id in seen_signal_ids:
                    continue
                seen_signal_ids.add(signal_id)
                merged.append(row)
        candidates = merged
        if symbol_key == "XAUUSD":
            _runtime_update(symbol_key, {"xau_grid_timeframe_used": "M5"})
        if not candidates:
            _runtime_update(
                symbol_key,
                {
                    "last_reject_stage": "candidate_search",
                    "last_reject_reason": "no_base_candidate",
                },
            )
        selected_actions: list[tuple[float, str, str, dict[str, Any], str]] = []
        blocked_reasons: list[str] = []

        for row in candidates:
            action_type = str(row["action_type"] or "OPEN_MARKET").upper()
            action_symbol = str(row["symbol"] or symbol)
            action_symbol_key = _normalize_symbol_key(action_symbol)
            base_reason = str(row["reason"] or "")
            is_canary_candidate = False
            is_force_test_trade = False
            if base_reason.startswith("canary_candidate"):
                parts = base_reason.split(":")
                target_account = parts[1] if len(parts) > 1 else ""
                target_magic = int(parts[2]) if len(parts) > 2 and str(parts[2]).isdigit() else None
                if target_account and str(account_id) != str(target_account):
                    continue
                if target_magic is not None and int(magic) != int(target_magic):
                    continue
                is_canary_candidate = True
            if base_reason.startswith("force_test_trade"):
                parts = base_reason.split(":")
                target_account = parts[1] if len(parts) > 1 else ""
                target_magic = int(parts[2]) if len(parts) > 2 and str(parts[2]).isdigit() else None
                if target_account and str(account_id) != str(target_account):
                    continue
                if target_magic is not None and int(magic) != int(target_magic):
                    continue
                is_force_test_trade = True
            ai_summary = json.loads(str(row["ai_summary"] or "{}"))
            probability = float(row["probability"] or ai_summary.get("probability") or 0.0)
            expected_value_r = float(row["expected_value_r"] or ai_summary.get("expected_value_r") or 0.0)
            _record_activity(action_symbol_key, "candidate_attempts", now)
            _record_activity(action_symbol_key, "candidate_count", now)
            _runtime_update(
                action_symbol_key,
                {
                    "last_strategy_checked": _strategy_key(action_symbol_key, str(row["setup"] or "")),
                    "last_candidate_reason": base_reason,
                    "last_candidate_score": float(row["action_score"] or 0.0),
                    "last_candidate_signal_id": str(row["signal_id"]),
                    "candidate_count_last_15m": _activity_count(action_symbol_key, "candidate_count", window_seconds=900),
                },
            )
            if action_symbol_key == "XAUUSD" and action_type == "OPEN_MARKET" and _is_grid_setup(str(row["setup"] or "")):
                _log(
                    logger,
                    "info",
                    "XAU_GRID_CANDIDATE",
                    symbol="XAUUSD",
                    signal_id=str(row["signal_id"]),
                    setup=str(row["setup"] or ""),
                    reason=base_reason,
                    probability=float(probability),
                    confluence=float(row["confluence_score"] or ai_summary.get("confluence_score") or 0.0),
                    spread=float(effective_spread_points),
                    session=session_name,
                )

            if action_type == "OPEN_MARKET":
                entry_blocked, entry_block_reason = _new_entry_block_state(now)
                if entry_blocked:
                    signal_id = str(row["signal_id"])
                    setup_name = str(row["setup"] or "").upper()
                    strategy_key = _strategy_key(action_symbol_key, setup_name)
                    queue.increment_block_reason(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=str(row["tf"] or timeframe_value).upper(),
                        reason=entry_block_reason,
                    )
                    _record_decision(
                        symbol_key=action_symbol_key,
                        signal_id=signal_id,
                        decision_type="entry_block",
                        reason=entry_block_reason,
                        session_name=session_name,
                        strategy_key=strategy_key,
                        setup=setup_name,
                        probability=probability,
                        expected_value_r=expected_value_r,
                        ai_mode=str(ai_runtime.get("last_ai_mode", "")),
                        extra={
                            "reject_stage": "startup_guard",
                            "startup_warmup_active": entry_block_reason == "startup_warmup",
                            "operator_control_state": _operator_control_status(),
                        },
                    )
                    _runtime_update(
                        action_symbol_key,
                        {
                            "last_reject_stage": "startup_guard",
                            "last_reject_reason": entry_block_reason,
                        },
                    )
                    blocked_reasons.append(f"{signal_id}:{entry_block_reason}")
                    continue
                setup_name = str(row["setup"] or "").upper()
                is_grid_setup = _is_grid_setup(setup_name)
                strategy_key = _strategy_key(action_symbol_key, setup_name)
                candidate_timeframe = str(row["tf"] or timeframe_value).upper()
                evaluation_timeframe = "M5" if (action_symbol_key == "XAUUSD" and is_grid_setup) else candidate_timeframe
                if action_symbol_key == "XAUUSD" and is_grid_setup and not (is_canary_candidate or is_force_test_trade):
                    runtime_guard_state = dict(symbol_runtime_state.get(action_symbol_key, {}))
                    performance_cooldown_active, performance_cooldown_updates = _resolve_runtime_guard_cooldown(
                        runtime_guard_state,
                        current_time=now,
                    )
                    if performance_cooldown_updates:
                        _runtime_update(action_symbol_key, performance_cooldown_updates)
                        runtime_guard_state.update(performance_cooldown_updates)
                    cooldown_enforced = bool(
                        runtime_guard_state.get("risk_reduction_active")
                        or runtime_guard_state.get("soft_dd_active")
                        or runtime_guard_state.get("hard_dd_active")
                        or performance_cooldown_active
                    )
                    cycle_state = queue.get_symbol_state(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                    )
                    recycle_until_raw = str(cycle_state.get("recycle_until") or "")
                    cycle_mode = str(cycle_state.get("cycle_mode") or "IDLE").upper()
                    if recycle_until_raw:
                        try:
                            recycle_until = _parse_iso(recycle_until_raw)
                        except Exception:
                            recycle_until = None
                        if cooldown_enforced and recycle_until is not None and now < recycle_until:
                            queue.update_symbol_state(
                                account=account_id,
                                magic=int(magic),
                                symbol_key=action_symbol_key,
                                timeframe=evaluation_timeframe,
                                updates={"last_block_reason": "cooldown_active"},
                            )
                            queue.increment_block_reason(
                                account=account_id,
                                magic=int(magic),
                                symbol_key=action_symbol_key,
                                timeframe=evaluation_timeframe,
                                reason="cooldown_active",
                            )
                            _runtime_update(
                                action_symbol_key,
                                {
                                    "last_reject_stage": "strategy_state",
                                    "last_reject_reason": "cooldown_active",
                                },
                            )
                            blocked_reasons.append(f"{signal_id}:cooldown_active")
                            continue
                        if recycle_until is not None and cycle_mode == "COOLDOWN":
                            queue.update_symbol_state(
                                account=account_id,
                                magic=int(magic),
                                symbol_key=action_symbol_key,
                                timeframe=evaluation_timeframe,
                                updates={"cycle_mode": "IDLE", "recycle_until": None},
                            )
                signal_id = str(row["signal_id"])
                side_hint = str(row["side"] or "").upper()
                pending_key = f"{action_symbol_key}:{setup_name}:{side_hint}:{evaluation_timeframe}"
                if base_reason == "candidate_scan_pending":
                    first_seen = pending_candidate_state.setdefault(pending_key, now)
                    pending_age = max(0.0, (now - first_seen).total_seconds())
                    if pending_age < float(policy.candidate_pending_timeout_seconds):
                        reason_code = "candidate_scan_pending"
                        queue.increment_block_reason(
                            account=account_id,
                            magic=int(magic),
                            symbol_key=action_symbol_key,
                            timeframe=evaluation_timeframe,
                            reason=reason_code,
                        )
                        _record_decision(
                            symbol_key=action_symbol_key,
                            signal_id=signal_id,
                            decision_type="entry_block",
                            reason=reason_code,
                            session_name=session_name,
                            strategy_key=strategy_key,
                            setup=setup_name,
                            probability=probability,
                            expected_value_r=expected_value_r,
                            ai_mode=str(ai_runtime.get("last_ai_mode", "")),
                            extra={"reject_stage": "candidate_pending", "pending_age_seconds": round(pending_age, 2)},
                        )
                        _runtime_update(
                            action_symbol_key,
                            {
                                "last_reject_stage": "candidate_pending",
                                "last_reject_reason": reason_code,
                            },
                        )
                        blocked_reasons.append(f"{row['signal_id']}:{reason_code}")
                        continue
                    base_reason = "candidate_pending_watchdog_escalated"
                    pending_candidate_state.pop(pending_key, None)
                    pending_candidate_state.pop(signal_id, None)
                else:
                    pending_candidate_state.pop(pending_key, None)
                    pending_candidate_state.pop(signal_id, None)
                governor_adjustments = _undertrading_adjustments(
                    account=account_id,
                    magic=int(magic),
                    symbol_key=action_symbol_key,
                    strategy_key=strategy_key,
                    is_grid=is_grid_setup,
                    session_name=session_name,
                    current_equity=current_equity,
                    account_snapshot=account_snapshot,
                )
                spread_limit_grid = _session_spread_limit(session_name=session_name, is_grid=True) * (
                    1.0 + float(governor_adjustments.get("spread_loosen_pct", 0.0))
                )
                spread_limit_other = _session_spread_limit(session_name=session_name, is_grid=False) * (
                    1.0 + float(governor_adjustments.get("spread_loosen_pct", 0.0))
                )
                confluence_floor = max(
                    0.30,
                    float(policy.min_confluence_score) - float(governor_adjustments.get("confluence_relax", 0.0)),
                )
                confluence_floor, min_probability_floor, min_ev_floor = _adaptive_thresholds(
                    confluence_floor=confluence_floor,
                    governor_adjustments=governor_adjustments,
                )
                optimizer_adjustments = _strategy_optimizer_adjustments(strategy_key)
                sensitivity_mult = clamp(float(optimizer_adjustments.get("candidate_sensitivity_mult", 1.0)), 0.80, 1.25)
                spread_limit_grid *= sensitivity_mult
                spread_limit_other *= sensitivity_mult
                learning_policy = _learning_policy_snapshot(symbol_key=action_symbol_key, setup_name=setup_name)
                pair_directive = dict(learning_policy.get("pair_directive") or {})
                setup_hour_directive = dict(learning_policy.get("setup_hour_directive") or {})
                expectancy_directive = dict(setup_hour_directive or pair_directive)
                execution_quality_runtime = dict(symbol_runtime_state.get(action_symbol_key, {}) or {})
                execution_quality_score = clamp(
                    float(execution_quality_runtime.get("slippage_quality_score", 0.55) or 0.55),
                    0.0,
                    1.0,
                )
                hour_expectancy_score = clamp(
                    float(
                        expectancy_directive.get(
                            "hour_expectancy_score",
                            pair_directive.get("hour_expectancy_score", 0.5),
                        )
                        or 0.5
                    ),
                    0.0,
                    1.0,
                )
                lane_expectancy_multiplier = clamp(
                    float(
                        expectancy_directive.get(
                            "lane_expectancy_multiplier",
                            pair_directive.get("lane_expectancy_multiplier", 1.0),
                        )
                        or 1.0
                    ),
                    0.80,
                    1.35,
                )
                strong_hours_sydney = {
                    int(item)
                    for item in expectancy_directive.get("strong_hours_sydney", [])
                    if str(item).strip().lstrip("-").isdigit()
                }
                weak_hours_sydney = {
                    int(item)
                    for item in expectancy_directive.get("weak_hours_sydney", [])
                    if str(item).strip().lstrip("-").isdigit()
                }
                current_sydney_hour = int(now.astimezone(SYDNEY).hour)
                spread_quality_adjust = 1.0
                if execution_quality_score >= float(policy.execution_quality_loosen_threshold):
                    loosen_pct = min(
                        float(policy.execution_spread_limit_loosen_pct),
                        (execution_quality_score - float(policy.execution_quality_loosen_threshold)) * 0.35,
                    )
                    spread_quality_adjust += max(0.0, loosen_pct)
                elif execution_quality_score <= float(policy.execution_quality_tighten_threshold):
                    tighten_pct = min(
                        float(policy.execution_spread_limit_tighten_pct),
                        (float(policy.execution_quality_tighten_threshold) - execution_quality_score) * 0.45,
                    )
                    spread_quality_adjust -= max(0.0, tighten_pct)
                if str(execution_quality_runtime.get("execution_quality_state") or "").upper() in {"DEGRADED", "POOR"}:
                    spread_quality_adjust = min(spread_quality_adjust, 0.95)
                if hour_expectancy_score >= 0.62:
                    spread_quality_adjust += min(0.03, max(0.0, lane_expectancy_multiplier - 1.0) * 0.10)
                    confluence_floor = max(0.30, confluence_floor - 0.02)
                elif hour_expectancy_score <= 0.42:
                    spread_quality_adjust -= 0.04
                    confluence_floor = min(0.95, confluence_floor + 0.03)
                    min_probability_floor = clamp(min_probability_floor + 0.02, 0.45, 0.95)
                if current_sydney_hour in strong_hours_sydney:
                    spread_quality_adjust += 0.02
                    confluence_floor = max(0.30, confluence_floor - 0.01)
                elif current_sydney_hour in weak_hours_sydney:
                    spread_quality_adjust -= 0.03
                    confluence_floor = min(0.95, confluence_floor + 0.02)
                    min_probability_floor = clamp(min_probability_floor + 0.01, 0.45, 0.95)
                spread_quality_adjust = clamp(spread_quality_adjust, 0.88, 1.10)
                spread_limit_grid *= spread_quality_adjust
                spread_limit_other *= spread_quality_adjust
                confluence_floor = clamp(
                    confluence_floor * float(optimizer_adjustments.get("confluence_floor_mult", 1.0)),
                    0.30,
                    0.95,
                )
                min_probability_floor = clamp(
                    min_probability_floor * float(optimizer_adjustments.get("probability_floor_mult", 1.0)),
                    0.45,
                    0.95,
                )
                if action_symbol_key == "XAUUSD" and is_grid_setup and session_name in set(policy.xau_grid_allowed_sessions):
                    xau_confluence_floor = float(policy.xau_grid_min_confluence_london)
                    if xau_confluence_floor > 1.0:
                        xau_confluence_floor = xau_confluence_floor / 5.0
                    if session_name in {"LONDON", "OVERLAP", "NEW_YORK"}:
                        confluence_floor = min(confluence_floor, clamp(xau_confluence_floor, 0.30, 0.95))
                        min_probability_floor = min(min_probability_floor, float(policy.xau_grid_min_probability_london))
                    else:
                        confluence_floor = max(confluence_floor, 0.76)
                        min_probability_floor = max(min_probability_floor, 0.60)
                    if (
                        bool(policy.xau_grid_new_cycle_soft_allow)
                        and session_name in {"LONDON", "OVERLAP", "NEW_YORK"}
                        and "NEW_CYCLE" in base_reason.upper()
                    ):
                        base_reason = "new_cycle_soft_allow"
                family_rejects = _recent_family_reject_count(
                    action_symbol_key,
                    setup_name,
                    now_ts=now,
                    window_minutes=int(policy.stale_idea_rejects_window_minutes),
                )
                queued_delivery_protected = _queue_row_delivery_protected(
                    row,
                    now_ts=now,
                    fair_ttl_seconds=max(
                        int(policy.queued_signal_fair_ttl_seconds),
                        int(policy.lease_seconds) * 2,
                    ),
                )
                if family_rejects >= int(policy.stale_idea_archive_threshold) and not queued_delivery_protected:
                    _log(
                        logger,
                        "warning",
                        "SIGNAL_STATE_ARCHIVED",
                        symbol=action_symbol_key,
                        signal_id=signal_id,
                        setup=setup_name,
                        reason="stale_idea_family_archived",
                        family_rejects=family_rejects,
                        state=str(row["status"] or "QUEUED"),
                    )
                    queue.mark_cancelled(signal_id=signal_id, reason="stale_idea_family_archived")
                    queue.increment_block_reason(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        reason="stale_idea_family_archived",
                    )
                    _record_decision(
                        symbol_key=action_symbol_key,
                        signal_id=signal_id,
                        decision_type="entry_block",
                        reason="stale_idea_family_archived",
                        session_name=session_name,
                        strategy_key=strategy_key,
                        setup=setup_name,
                        probability=probability,
                        expected_value_r=expected_value_r,
                        extra={"reject_stage": "stale_idea"},
                    )
                    _record_reject_activity(action_symbol_key, "stale_idea_family_archived", now_ts=now)
                    blocked_reasons.append(f"{row['signal_id']}:stale_idea_family_archived")
                    continue
                if family_rejects >= int(policy.stale_idea_archive_threshold) and queued_delivery_protected:
                    _log(
                        logger,
                        "info",
                        "SIGNAL_STATE_PROTECTED",
                        symbol=action_symbol_key,
                        signal_id=signal_id,
                        setup=setup_name,
                        reason="queued_delivery_window_active",
                        state=str(row["status"] or "QUEUED"),
                        family_rejects=family_rejects,
                    )
                if family_rejects >= int(policy.stale_idea_rejects_threshold):
                    confluence_floor = max(0.30, confluence_floor - 0.03)
                    min_probability_floor = max(0.45, min_probability_floor - 0.02)
                    min_ev_floor = max(0.05, min_ev_floor - 0.03)
                if queue.has_open_lock(account=account_id, magic=int(magic), symbol_key=action_symbol_key):
                    reason_code = "open_lock_active"
                    queue.increment_block_reason(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        reason=reason_code,
                    )
                    _record_decision(
                        symbol_key=action_symbol_key,
                        signal_id=signal_id,
                        decision_type="entry_block",
                        reason=reason_code,
                        session_name=session_name,
                        strategy_key=strategy_key,
                        setup=setup_name,
                        probability=probability,
                        expected_value_r=expected_value_r,
                        ai_mode=str(ai_runtime.get("last_ai_mode", "")),
                        extra={"starvation_mode": bool(governor_adjustments.get("active", False)), "reject_stage": "open_lock"},
                    )
                    _runtime_update(action_symbol_key, {"last_reject_stage": "open_lock", "last_reject_reason": reason_code})
                    blocked_reasons.append(f"{row['signal_id']}:{reason_code}")
                    continue
                side = str(row["side"] or "").upper()
                entry_price = float(row["entry_price"] or 0.0)
                if entry_price <= 0:
                    if entry_hint > 0:
                        entry_price = entry_hint
                    elif float(row["sl"] or 0.0) > 0 and float(row["tp"] or 0.0) > 0:
                        entry_price = (float(row["sl"]) + float(row["tp"])) * 0.5
                original_entry_price = entry_price
                sl_price = float(row["sl"] or 0.0)
                tp_price = float(row["tp"] or 0.0)
                if isinstance(row, sqlite3.Row):
                    setup_type_hint = str(row["setup_type"] or "").lower() if "setup_type" in row.keys() else ""
                elif isinstance(row, dict):
                    setup_type_hint = str(row.get("setup_type") or "").lower()
                else:
                    setup_type_hint = ""
                try:
                    queued_validation_snapshot = json.loads(str(row["validation_json"] or "{}"))
                except Exception:
                    queued_validation_snapshot = {}
                if not isinstance(queued_validation_snapshot, dict):
                    queued_validation_snapshot = {}
                queued_confluence = _safe_float(
                    row["confluence_score"] if isinstance(row, sqlite3.Row) and "confluence_score" in row.keys() else row.get("confluence_score") if isinstance(row, dict) else 0.0,
                    0.0,
                )
                delivery_reanchored = False
                reanchor_gap_ratio = 0.0
                reanchor_sl_offset = 0.0
                reanchor_tp_offset = 0.0
                validation_input = StopValidationInput(
                    symbol=action_symbol,
                    side=side,
                    entry_price=entry_price,
                    sl=sl_price,
                    tp=tp_price,
                    spread_points=effective_spread_points,
                    live_bid=_safe_float(account_snapshot.get("bid"), 0.0),
                    live_ask=_safe_float(account_snapshot.get("ask"), 0.0),
                    safety_buffer_points=int(policy.safety_buffer_points),
                    allow_tp_none=True,
                    push_sl_if_too_close=True,
                )
                action_rule = _symbol_rule_with_snapshot_overrides(
                    resolve_symbol_rule(action_symbol, symbol_rules),
                    account_snapshot,
                )
                if is_canary_candidate or is_force_test_trade:
                    if action_symbol_key == "BTCUSD":
                        action_rule = replace(
                            action_rule,
                            min_stop_points=min(int(action_rule.min_stop_points), 40),
                            freeze_points=min(int(action_rule.freeze_points), 20),
                        )
                    elif action_symbol_key == "XAUUSD":
                        action_rule = replace(
                            action_rule,
                            min_stop_points=min(int(action_rule.min_stop_points), 20),
                            freeze_points=min(int(action_rule.freeze_points), 10),
                        )
                scalp_delivery_reason, scalp_delivery_meta = _scalp_delivery_entry_guard_reason(
                    setup=str(row["setup"] or ""),
                    setup_type=str(setup_type_hint),
                    symbol_key=action_symbol_key,
                    side=side,
                    reference_entry_price=original_entry_price,
                    live_entry_price=float(entry_hint or entry_price or 0.0),
                    stop_price=float(sl_price),
                    tp_price=float(tp_price),
                    spread_points=float(effective_spread_points),
                    typical_spread_points=float(action_rule.typical_spread_points),
                    point_size=float(action_rule.point),
                    reanchor_drift_stop_ratio=float(policy.scalp_delivery_reanchor_drift_stop_ratio),
                    block_drift_stop_ratio=float(policy.scalp_delivery_block_drift_stop_ratio),
                    reanchor_spread_mult=float(policy.scalp_delivery_reanchor_spread_mult),
                    block_spread_mult=float(policy.scalp_delivery_block_spread_mult),
                    spread_to_target_ratio_cap=float(policy.scalp_delivery_spread_to_target_ratio_cap),
                )
                if scalp_delivery_meta:
                    queued_validation_snapshot.update(scalp_delivery_meta)
                if scalp_delivery_reason == "scalp_entry_reanchor" and entry_hint > 0 and entry_price > 0:
                    reanchor_gap_ratio = abs(float(entry_hint) - float(entry_price)) / max(abs(float(entry_hint)), 1.0)
                    reanchor_sl_offset = abs(float(entry_price) - float(sl_price)) if sl_price > 0 else 0.0
                    reanchor_tp_offset = abs(float(tp_price) - float(entry_price)) if tp_price > 0 else 0.0
                    if reanchor_sl_offset > 0.0:
                        entry_price = float(entry_hint)
                        if side == "BUY":
                            sl_price = max(0.0, entry_price - reanchor_sl_offset)
                            tp_price = (entry_price + reanchor_tp_offset) if tp_price > 0 and reanchor_tp_offset > 0 else 0.0
                        elif side == "SELL":
                            sl_price = entry_price + reanchor_sl_offset
                            tp_price = (entry_price - reanchor_tp_offset) if tp_price > 0 and reanchor_tp_offset > 0 else 0.0
                        delivery_reanchored = True
                elif scalp_delivery_reason in {"scalp_entry_drift_too_high", "scalp_spread_eats_target"}:
                    queue.update_scoring(
                        signal_id=str(row["signal_id"]),
                        confluence_score=float(queued_confluence),
                        action_score=0.0,
                        risk_cost=0.0,
                        reason=f"blocked:{scalp_delivery_reason}",
                    )
                    queue.update_symbol_state(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        updates={"last_block_reason": str(scalp_delivery_reason)},
                    )
                    queue.increment_block_reason(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        reason=str(scalp_delivery_reason),
                    )
                    _record_decision(
                        symbol_key=action_symbol_key,
                        signal_id=str(row["signal_id"]),
                        decision_type="entry_block",
                        reason=str(scalp_delivery_reason),
                        session_name=session_name,
                        strategy_key=str(strategy_key),
                        setup=str(row["setup"] or ""),
                        probability=float(probability),
                        expected_value_r=float(expected_value_r),
                        confluence=float(queued_confluence),
                        ai_mode=str(ai_runtime.get("last_ai_mode", "")),
                        extra={"reject_stage": "delivery_entry_quality", **dict(scalp_delivery_meta)},
                    )
                    _runtime_update(
                        action_symbol_key,
                        {
                            "last_reject_stage": "delivery_entry_quality",
                            "last_reject_reason": str(scalp_delivery_reason),
                            **dict(scalp_delivery_meta),
                        },
                    )
                    blocked_reasons.append(f"{row['signal_id']}:{scalp_delivery_reason}")
                    continue
                validation_input = StopValidationInput(
                    symbol=action_symbol,
                    side=side,
                    entry_price=entry_price,
                    sl=sl_price,
                    tp=tp_price,
                    spread_points=effective_spread_points,
                    live_bid=_safe_float(account_snapshot.get("bid"), 0.0),
                    live_ask=_safe_float(account_snapshot.get("ask"), 0.0),
                    safety_buffer_points=int(policy.safety_buffer_points),
                    allow_tp_none=True,
                    push_sl_if_too_close=True,
                )
                validation = validate_and_normalize_stops(validation_input, action_rule)
                validation_snapshot = validation.snapshot(entry_price=entry_price)
                if delivery_reanchored:
                    validation_snapshot.update(
                        {
                            "delivery_reanchored": True,
                            "entry_reference_original": original_entry_price,
                            "entry_reference_live": entry_price,
                            "reanchor_gap_ratio": reanchor_gap_ratio,
                            "reanchor_sl_offset": reanchor_sl_offset,
                            "reanchor_tp_offset": reanchor_tp_offset,
                        }
                    )
                    _runtime_update(
                        action_symbol_key,
                        {
                            "delivery_reanchored": True,
                            "delivery_reanchor_gap_ratio": reanchor_gap_ratio,
                            "delivery_reanchor_entry": entry_price,
                        },
                    )
                    _log(
                        logger,
                        "info",
                        "TRADE_DELIVERY_REANCHORED",
                        symbol=action_symbol_key,
                        signal_id=str(row["signal_id"]),
                        original_entry=original_entry_price,
                        live_entry=entry_price,
                        gap_ratio=reanchor_gap_ratio,
                    )
                max_slippage = min(int(row["max_slippage_points"] or 0) or action_rule.max_slippage_points, int(action_rule.max_slippage_points))
                fallback_open_without_stops = False
                post_open_sl = 0.0
                post_open_tp = 0.0
                force_open_without_stops = bool(
                    queued_validation_snapshot.get("fallback_open_without_stops")
                ) and bool(
                    queued_validation_snapshot.get("broker_invalid_stops_retry")
                    or queued_validation_snapshot.get("retry_parent_signal_id")
                )
                if force_open_without_stops and entry_price > 0 and side in {"BUY", "SELL"}:
                    fallback_open_without_stops = True
                    post_open_sl = float(
                        queued_validation_snapshot.get("post_open_sl")
                        or sl_price
                        or 0.0
                    )
                    post_open_tp = float(
                        queued_validation_snapshot.get("post_open_tp")
                        or tp_price
                        or 0.0
                    )
                    validation_snapshot = dict(queued_validation_snapshot)
                    validation_snapshot.update(
                        {
                            "fallback_open_without_stops": True,
                            "fallback_reason": str(
                                queued_validation_snapshot.get("fallback_reason")
                                or validation.reason
                                or "broker_invalid_stops_retry"
                            ),
                            "post_open_sl": post_open_sl,
                            "post_open_tp": post_open_tp,
                        }
                    )
                    queue.update_validation(
                        signal_id=str(row["signal_id"]),
                        normalized_sl=0.0,
                        normalized_tp=0.0,
                        validation_snapshot=validation_snapshot,
                        max_slippage_points=max_slippage,
                    )
                elif not validation.valid or validation.normalized_sl is None:
                    if bool(policy.allow_open_without_stops_fallback) and entry_price > 0 and side in {"BUY", "SELL"}:
                        fallback_validation = validate_and_normalize_stops(
                            StopValidationInput(
                                symbol=action_symbol,
                                side=side,
                                entry_price=entry_price,
                                sl=0.0,
                                tp=0.0,
                                spread_points=effective_spread_points,
                                live_bid=_safe_float(account_snapshot.get("bid"), 0.0),
                                live_ask=_safe_float(account_snapshot.get("ask"), 0.0),
                                safety_buffer_points=int(policy.safety_buffer_points),
                                allow_tp_none=True,
                                push_sl_if_too_close=True,
                            ),
                            action_rule,
                        )
                        if fallback_validation.valid and fallback_validation.normalized_sl is not None:
                            fallback_open_without_stops = True
                            post_open_sl = float(fallback_validation.normalized_sl)
                            post_open_tp = float(fallback_validation.normalized_tp or 0.0)
                            validation_snapshot = fallback_validation.snapshot(entry_price=entry_price)
                            validation_snapshot.update(
                                {
                                    "fallback_open_without_stops": True,
                                    "fallback_reason": validation.reason,
                                    "post_open_sl": post_open_sl,
                                    "post_open_tp": post_open_tp,
                                }
                            )
                            queue.update_validation(
                                signal_id=str(row["signal_id"]),
                                normalized_sl=0.0,
                                normalized_tp=0.0,
                                validation_snapshot=validation_snapshot,
                                max_slippage_points=max_slippage,
                            )
                        else:
                            queue.mark_failed_validation(
                                signal_id=str(row["signal_id"]),
                                reason=f"fallback_failed:{fallback_validation.reason}",
                                snapshot=fallback_validation.snapshot(entry_price=entry_price),
                            )
                            queue.increment_block_reason(
                                account=account_id,
                                magic=int(magic),
                                symbol_key=action_symbol_key,
                                timeframe=evaluation_timeframe,
                                reason=f"fallback_failed:{fallback_validation.reason}",
                            )
                            _record_decision(
                                symbol_key=action_symbol_key,
                                signal_id=str(row["signal_id"]),
                                decision_type="entry_block",
                                reason=f"fallback_failed:{fallback_validation.reason}",
                                session_name=session_name,
                                strategy_key=strategy_key,
                                setup=setup_name,
                                probability=probability,
                                expected_value_r=expected_value_r,
                                ai_mode=str(ai_runtime.get("last_ai_mode", "")),
                                extra={"starvation_mode": bool(governor_adjustments.get("active", False)), "reject_stage": "stop_validation"},
                            )
                            _runtime_update(
                                action_symbol_key,
                                {
                                    "last_reject_stage": "stop_validation",
                                    "last_reject_reason": f"fallback_failed:{fallback_validation.reason}",
                                    "rejected_due_to_stop_width": True,
                                },
                            )
                            blocked_reasons.append(f"{row['signal_id']}:fallback_failed:{fallback_validation.reason}")
                            continue
                    else:
                        queue.mark_failed_validation(signal_id=str(row["signal_id"]), reason=validation.reason, snapshot=validation_snapshot)
                        _log(
                            logger,
                            "info",
                            "TRADE_DELIVERY_BLOCKED",
                            symbol=action_symbol_key,
                            signal_id=str(row["signal_id"]),
                            reason=str(validation.reason),
                            stage="stop_validation",
                        )
                        queue.increment_block_reason(
                            account=account_id,
                            magic=int(magic),
                            symbol_key=action_symbol_key,
                            timeframe=evaluation_timeframe,
                            reason=str(validation.reason),
                        )
                        _record_decision(
                            symbol_key=action_symbol_key,
                            signal_id=str(row["signal_id"]),
                            decision_type="entry_block",
                            reason=str(validation.reason),
                            session_name=session_name,
                            strategy_key=strategy_key,
                            setup=setup_name,
                            probability=probability,
                            expected_value_r=expected_value_r,
                            ai_mode=str(ai_runtime.get("last_ai_mode", "")),
                            extra={"starvation_mode": bool(governor_adjustments.get("active", False)), "reject_stage": "stop_validation"},
                        )
                        _runtime_update(
                            action_symbol_key,
                            {
                                "last_reject_stage": "stop_validation",
                                "last_reject_reason": str(validation.reason),
                                "rejected_due_to_stop_width": "stop" in str(validation.reason).lower(),
                            },
                        )
                        blocked_reasons.append(f"{row['signal_id']}:{validation.reason}")
                        continue
                else:
                    normalized_tp = float(validation.normalized_tp) if validation.normalized_tp is not None else 0.0
                    queue.update_validation(
                        signal_id=str(row["signal_id"]),
                        normalized_sl=float(validation.normalized_sl),
                        normalized_tp=normalized_tp if normalized_tp > 0 else 0.0,
                        validation_snapshot=validation_snapshot,
                        max_slippage_points=max_slippage,
                    )

                try:
                    row_context = json.loads(str(row["context_json"] or "{}"))
                except Exception:
                    row_context = {}
                if not isinstance(row_context, dict):
                    row_context = {}
                spread_reference_points = _safe_float(
                    row_context.get("spread_reference_points"),
                    max(
                        float(action_rule.typical_spread_points),
                        _safe_float(row_context.get("spread_points"), effective_spread_points),
                        1.0,
                    ),
                )
                spread_atr_points = _safe_float(row_context.get("spread_atr_points"), 0.0)

                risk_pct, boost_active = _effective_risk_pct(
                    equity=current_equity,
                    account=account_id,
                    magic=int(magic),
                    symbol_key=action_symbol_key,
                )
                if is_canary_candidate or is_force_test_trade:
                    risk_pct = max(float(risk_pct), float(policy.base_risk_pct))
                setup_name = str(row["setup"] or "").upper()
                if action_symbol_key == "XAUUSD" and "GRID" in setup_name:
                    risk_pct = max(risk_pct, min(float(policy.xau_grid_cycle_risk_pct), float(policy.max_risk_pct)))
                budget_usd = clamp(float(current_equity) * risk_pct, float(policy.min_budget_usd), float(policy.max_budget_usd))
                risk_stop_price = post_open_sl if fallback_open_without_stops else float(validation.normalized_sl or 0.0)
                estimated_loss = estimate_loss_usd(
                    entry_price=entry_price,
                    stop_price=risk_stop_price,
                    lot=float(row["lot"] or 0.0),
                    rule=action_rule,
                )
                risk_cost = estimated_loss / max(budget_usd, 1e-6)
                stop_distance_points_live = abs(float(entry_price) - float(risk_stop_price)) / max(float(action_rule.point), 1e-9)
                spread_penalty_r_live = float(effective_spread_points) / max(float(stop_distance_points_live), 1.0)
                net_expected_value_r = float(
                    _safe_float(
                        row_context.get("net_expected_value_r"),
                        float(expected_value_r) - float(spread_penalty_r_live),
                    )
                )
                confluence = _confluence_score(row, probability=probability, expected_value_r=net_expected_value_r)
                runtime_market_data_symbol = _market_data_for_symbol(action_symbol_key)
                shadow_context = _shadow_context_for_candidate(
                    account=account_id,
                    magic=int(magic),
                    symbol_key=action_symbol_key,
                    side=side,
                    session_name=session_name,
                    setup_name=setup_name,
                    regime=str(row["regime"] or ""),
                    probability=probability,
                    expected_value_r=net_expected_value_r,
                    news_status=str(row["news_status"] or ""),
                    account_snapshot=account_snapshot,
                    runtime_market_data=runtime_market_data_symbol,
                )
                ranking_bonus = float(shadow_context.get("ranking_bonus", 0.0))
                if ranking_bonus > 0:
                    confluence = clamp(confluence + min(0.03, ranking_bonus * 0.5), 0.0, 1.0)
                    confluence_floor = max(0.30, confluence_floor - min(0.03, ranking_bonus * 0.5))
                    min_probability_floor = max(0.35, min_probability_floor - min(0.02, ranking_bonus * 0.35))
                elif ranking_bonus < 0:
                    min_probability_floor = min(0.95, min_probability_floor + min(0.02, abs(ranking_bonus) * 0.5))
                _runtime_update(
                    action_symbol_key,
                    {
                        "shadow_system_enabled": bool(policy.shadow_system_enabled),
                        "shadow_alignment_score": float(shadow_context.get("cross_asset_alignment_score", 0.0)),
                        "shadow_alignment_state": str(shadow_context.get("cross_asset_alignment_state", "NEUTRAL")),
                        "shadow_alignment_detail": list(shadow_context.get("cross_asset_alignment_detail", [])),
                        "behavioral_regime": str(shadow_context.get("behavioral_regime", "BALANCED")),
                        "crowding_bias": str(shadow_context.get("crowding_bias", "neutral")),
                        "social_sentiment_extreme": float(shadow_context.get("social_sentiment_extreme", 0.0)),
                        "ghost_order_book_proxy": float(shadow_context.get("ghost_order_book_proxy", 0.0)),
                        "predicted_liquidity_hunt_score": float(shadow_context.get("predicted_liquidity_hunt_score", 0.0)),
                        "spread_penalty_r_live": float(spread_penalty_r_live),
                        "net_expected_value_r": float(net_expected_value_r),
                        "spread_reference_points": float(spread_reference_points),
                        "spread_atr_points": float(spread_atr_points),
                        "latency_edge_ms": int(shadow_context.get("latency_edge_ms", 0) or 0),
                        "latency_edge_detected": bool(shadow_context.get("latency_edge_detected", False)),
                        "snapshot_age_seconds": shadow_context.get("snapshot_age_seconds"),
                        "shadow_ranking_bonus": float(ranking_bonus),
                        "runtime_market_data_latency_ms": runtime_market_data_symbol.get("runtime_market_data_latency_ms"),
                    },
                )
                if action_symbol_key == "BTCUSD":
                    min_probability_floor = max(float(min_probability_floor), float(policy.btc_min_ai_confidence))
                    btc_policy_block, btc_policy_meta = _btc_entry_policy_block_reason(
                        account=account_id,
                        magic=int(magic),
                        setup_name=setup_name,
                        side=side,
                        session_name=session_name,
                        now_utc=now,
                        probability=probability,
                        confluence=confluence,
                        expected_value_r=net_expected_value_r,
                        spread_points=effective_spread_points,
                        point_size=float(action_rule.point),
                        current_equity=current_equity,
                        quote_state=symbol_market_quote_state.get(action_symbol_key, {}),
                    )
                    _runtime_update(action_symbol_key, btc_policy_meta)
                    if btc_policy_block:
                        queue.update_scoring(
                            signal_id=str(row["signal_id"]),
                            confluence_score=confluence,
                            action_score=0.0,
                            risk_cost=risk_cost,
                            reason=f"blocked:{btc_policy_block}",
                        )
                        queue.update_symbol_state(
                            account=account_id,
                            magic=int(magic),
                            symbol_key=action_symbol_key,
                            timeframe=evaluation_timeframe,
                            updates={"last_block_reason": str(btc_policy_block)},
                        )
                        queue.increment_block_reason(
                            account=account_id,
                            magic=int(magic),
                            symbol_key=action_symbol_key,
                            timeframe=evaluation_timeframe,
                            reason=str(btc_policy_block),
                        )
                        _record_decision(
                            symbol_key=action_symbol_key,
                            signal_id=str(row["signal_id"]),
                            decision_type="entry_block",
                            reason=str(btc_policy_block),
                            session_name=session_name,
                            strategy_key=strategy_key,
                            setup=setup_name,
                            probability=probability,
                            expected_value_r=expected_value_r,
                            confluence=confluence,
                            ai_mode=str(ai_runtime.get("last_ai_mode", "")),
                            extra={"reject_stage": "btc_policy"},
                        )
                        _runtime_update(
                            action_symbol_key,
                            {
                                "last_reject_stage": "btc_policy",
                                "last_reject_reason": str(btc_policy_block),
                            },
                        )
                        _record_reject_activity(action_symbol_key, str(btc_policy_block), now_ts=now)
                        blocked_reasons.append(f"{row['signal_id']}:{btc_policy_block}")
                        continue
                omega_spread_ref = float(spread_limit_grid if is_grid_setup else spread_limit_other)
                omega_state_payload = _omega_state_for_candidate(
                    symbol_key=action_symbol_key,
                    side=side,
                    regime=str(row["regime"] or ""),
                    probability=probability,
                    expected_value_r=expected_value_r,
                    spread_points=effective_spread_points,
                    spread_ref=omega_spread_ref,
                    risk_cost=risk_cost,
                    news_status=str(row["news_status"] or ""),
                )
                omega_label = str(omega_state_payload.get("label", "RANGING")).upper()
                news_status_text = str(row["news_status"] or "").lower()
                if (
                    action_symbol_key == "BTCUSD"
                    and _is_weekend_market_mode(now)
                    and omega_label == "NEWS_SHOCK"
                    and not any(token in news_status_text for token in ("blocked", "high", "fomc", "nfp", "cpi", "shock"))
                ):
                    omega_label = "VOLATILE" if effective_spread_points >= (omega_spread_ref * 0.9) else "RANGING"
                    omega_state_payload["label"] = omega_label
                    _runtime_update(
                        action_symbol_key,
                        {
                            "omega_regime": omega_label,
                            "omega_override_reason": "btc_weekend_routine_volatility",
                        },
                    )
                early_news_allowed, early_news_reason = _news_allowed(
                    news_status=str(row["news_status"] or ""),
                    probability=probability,
                    confluence=confluence,
                    spread_points=effective_spread_points,
                    rule=action_rule,
                    risk_cost=risk_cost,
                )
                xau_high_conf_news_override = (
                    action_symbol_key == "XAUUSD"
                    and str(policy.news_mode).upper() == "ALLOW_HIGH_CONF"
                    and float(probability) >= max(float(policy.news_high_conf_probability), float(policy.news_armed_min_probability))
                    and (
                        "GRID" in str(row["setup"] or "").upper()
                        or float(confluence) >= max(float(policy.news_high_conf_confluence), float(policy.news_armed_min_confluence))
                        or float(row.get("confluence_score") or ai_summary.get("confluence_score") or 0.0) >= 3.0
                    )
                )
                setup_upper = str(setup_name or strategy_key or "").upper()
                btc_selective_family_allowed = action_symbol_key == "BTCUSD" and any(
                    token in setup_upper
                    for token in (
                        "BTC_TREND_SCALP",
                        "BTC_MOMENTUM_CONTINUATION",
                        "BTC_NY_LIQUIDITY",
                        "BTC_TOKYO_DRIFT_SCALP",
                        "BTC_LONDON_IMPULSE_SCALP",
                        "BTC_RANGE_EXPANSION",
                        "BTC_LIQUIDITY_SWEEP_FADE",
                        "BTC_EXHAUSTION_REVERSION",
                        "BTC_WEEKEND_BREAKOUT",
                        "BTC_WEEKEND_RECLAIM",
                        "BTC_WEEKEND_BREAKOUT_RECLAIM",
                    )
                )
                btc_weekend_spread_fraction = _spread_price_fraction(
                    spread_points=effective_spread_points,
                    point_size=float(action_rule.point),
                    reference_price=entry_price if entry_price > 0 else float(row["entry_price"] or 0.0),
                )
                selective_probability_floor = max(
                    float(policy.btc_min_ai_confidence) - (0.06 if btc_selective_family_allowed else 0.02),
                    0.53 if btc_selective_family_allowed else 0.56,
                )
                selective_confluence_floor = 0.54 if btc_selective_family_allowed else 0.58
                selective_expected_value_floor = 0.15 if btc_selective_family_allowed else 0.20
                selective_spread_fraction_cap = 0.00060 if btc_selective_family_allowed else 0.00050
                selective_spread_multiple_cap = 22.0 if btc_selective_family_allowed else 18.0
                session_upper = str(session_name or "").upper()
                allow_btc_selective_volatile_delivery = (
                    action_symbol_key == "BTCUSD"
                    and float(probability) >= selective_probability_floor
                    and float(confluence) >= selective_confluence_floor
                    and float(expected_value_r) >= selective_expected_value_floor
                    and (
                        btc_weekend_spread_fraction <= selective_spread_fraction_cap
                        or effective_spread_points < max(float(action_rule.typical_spread_points), 1.0) * selective_spread_multiple_cap
                    )
                    and (
                        session_upper in ({str(item).upper() for item in policy.btc_trade_sessions} | {"SYDNEY"})
                        or _btc_trade_window_allowed(now)
                    )
                )
                if omega_label == "NEWS_SHOCK" and (
                    (early_news_allowed and action_symbol_key != "BTCUSD")
                    or xau_high_conf_news_override
                ):
                    omega_label = "NEWS_ARMED_OK"
                    omega_state_payload["label"] = omega_label
                    _runtime_update(
                        action_symbol_key,
                        {
                            "omega_regime": omega_label,
                            "omega_override_reason": (
                                "xau_high_conf_news_shock_defer"
                                if xau_high_conf_news_override and not early_news_allowed
                                else f"news_override:{early_news_reason}"
                            ),
                        },
                    )
                elif (
                    omega_label == "NEWS_SHOCK"
                    and action_symbol_key == "USOIL"
                    and str(policy.news_mode).upper() == "ALLOW_HIGH_CONF"
                ):
                    omega_label = "NEWS_ARMED_OK"
                    omega_state_payload["label"] = omega_label
                    _runtime_update(
                        action_symbol_key,
                        {
                            "omega_regime": omega_label,
                            "omega_override_reason": "oil_news_armed_threshold_check",
                        },
                    )
                elif omega_label == "NEWS_SHOCK" and allow_btc_selective_volatile_delivery:
                    omega_label = "VOLATILE"
                    omega_state_payload["label"] = omega_label
                    _runtime_update(
                        action_symbol_key,
                        {
                            "omega_regime": omega_label,
                            "omega_override_reason": "btc_selective_news_shock_defer",
                            "omega_spread_price_fraction": btc_weekend_spread_fraction,
                            "omega_selective_family_allowed": bool(btc_selective_family_allowed),
                        },
                    )
                if omega_label == "NEWS_SHOCK" and not (is_canary_candidate or is_force_test_trade):
                    queue.update_scoring(
                        signal_id=str(row["signal_id"]),
                        confluence_score=confluence,
                        action_score=0.0,
                        risk_cost=risk_cost,
                        reason="blocked:omega_news_shock",
                    )
                    queue.increment_block_reason(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        reason="omega_news_shock",
                    )
                    queue.update_symbol_state(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        updates={"last_block_reason": "omega_news_shock"},
                    )
                    _runtime_update(action_symbol_key, {"last_reject_stage": "omega", "last_reject_reason": "omega_news_shock"})
                    _record_reject_activity(action_symbol_key, "omega_news_shock", now_ts=now)
                    blocked_reasons.append(f"{row['signal_id']}:omega_news_shock")
                    continue
                volatile_pause_until_raw = str(symbol_runtime_state.get(action_symbol_key, {}).get("omega_volatile_pause_until") or "")
                volatile_pause_until = None
                if volatile_pause_until_raw:
                    try:
                        volatile_pause_until = _parse_iso(volatile_pause_until_raw)
                    except Exception:
                        volatile_pause_until = None
                if omega_label == "VOLATILE" and not (is_canary_candidate or is_force_test_trade):
                    nas_selective_volatile_delivery = (
                        action_symbol_key == "NAS100"
                        and float(probability) >= 0.70
                        and float(confluence) >= 0.55
                        and float(expected_value_r) >= 0.25
                        and effective_spread_points <= max(90.0, float(omega_spread_ref) * 1.20)
                        and session_upper in {"SYDNEY", "TOKYO", "LONDON", "OVERLAP", "NEW_YORK"}
                    )
                    allow_btc_selective_volatile_delivery = (
                        action_symbol_key == "BTCUSD"
                        and allow_btc_selective_volatile_delivery
                    )
                    allow_btc_weekend_volatile_delivery = (
                        action_symbol_key == "BTCUSD"
                        and _is_weekend_market_mode(now)
                        and float(probability) >= 0.58
                        and (
                            btc_weekend_spread_fraction <= 0.00045
                            or effective_spread_points < max(float(action_rule.typical_spread_points), 1.0) * 20.0
                        )
                    )
                    if allow_btc_weekend_volatile_delivery:
                        _runtime_update(
                            action_symbol_key,
                            {
                                "omega_regime": "VOLATILE_WEEKEND_OK",
                                "omega_override_reason": "btc_weekend_bounded_volatile_delivery",
                                "omega_spread_price_fraction": btc_weekend_spread_fraction,
                            },
                        )
                        omega_label = "VOLATILE_WEEKEND_OK"
                    elif allow_btc_selective_volatile_delivery:
                        _runtime_update(
                            action_symbol_key,
                            {
                                "omega_regime": "VOLATILE_SELECTIVE_OK",
                                "omega_override_reason": "btc_selective_price_action_volatile_delivery" if btc_selective_family_allowed else "btc_selective_bounded_volatile_delivery",
                                "omega_spread_price_fraction": btc_weekend_spread_fraction,
                                "omega_selective_family_allowed": bool(btc_selective_family_allowed),
                            },
                        )
                        omega_label = "VOLATILE_SELECTIVE_OK"
                    elif nas_selective_volatile_delivery:
                        _runtime_update(
                            action_symbol_key,
                            {
                                "omega_regime": "VOLATILE_SELECTIVE_OK",
                                "omega_override_reason": "nas_selective_bounded_volatile_delivery",
                                "omega_spread_points": float(effective_spread_points),
                            },
                        )
                        omega_label = "VOLATILE_SELECTIVE_OK"
                    if omega_label == "VOLATILE_WEEKEND_OK":
                        pass
                    elif omega_label == "VOLATILE_SELECTIVE_OK":
                        pass
                    elif omega_label == "VOLATILE":
                        if volatile_pause_until is None or now >= volatile_pause_until:
                            volatile_pause_until = now + timedelta(seconds=max(5, int(policy.omega_volatile_entry_pause_seconds)))
                            _runtime_update(action_symbol_key, {"omega_volatile_pause_until": _to_iso(volatile_pause_until)})
                        if now < volatile_pause_until and effective_spread_points >= (omega_spread_ref * 0.85):
                            queue.update_scoring(
                                signal_id=str(row["signal_id"]),
                                confluence_score=confluence,
                                action_score=0.0,
                                risk_cost=risk_cost,
                                reason="blocked:omega_volatile_pause",
                            )
                            queue.increment_block_reason(
                                account=account_id,
                                magic=int(magic),
                                symbol_key=action_symbol_key,
                                timeframe=evaluation_timeframe,
                                reason="omega_volatile_pause",
                            )
                            queue.update_symbol_state(
                                account=account_id,
                                magic=int(magic),
                                symbol_key=action_symbol_key,
                                timeframe=evaluation_timeframe,
                                updates={"last_block_reason": "omega_volatile_pause"},
                            )
                            _runtime_update(action_symbol_key, {"last_reject_stage": "omega", "last_reject_reason": "omega_volatile_pause"})
                            _record_reject_activity(action_symbol_key, "omega_volatile_pause", now_ts=now)
                            blocked_reasons.append(f"{row['signal_id']}:omega_volatile_pause")
                            continue
                snapshot_age_seconds = 0.0
                created_at_raw = str(row["created_at"] or "")
                if created_at_raw:
                    try:
                        created_at = _parse_iso(created_at_raw)
                        snapshot_age_seconds = max(0.0, (now - created_at).total_seconds())
                    except Exception:
                        snapshot_age_seconds = 0.0
                strategy_specific_block, strategy_meta = _strategy_specific_block_reason(
                    strategy_key=strategy_key,
                    session_name=session_name,
                    now_utc=now,
                    setup_name=setup_name,
                    reason_text=base_reason,
                    side=side,
                    regime=str(row["regime"] or ""),
                    spread_points=effective_spread_points,
                    confluence=confluence,
                    probability=probability,
                    expected_value_r=expected_value_r,
                    risk_cost=risk_cost,
                    news_status=str(row["news_status"] or ""),
                    snapshot_age_seconds=snapshot_age_seconds,
                    spread_loosen_pct=float(governor_adjustments.get("spread_loosen_pct", 0.0)),
                    confluence_relax=float(governor_adjustments.get("confluence_relax", 0.0))
                    + (0.10 if bool(governor_adjustments.get("disable_low_weight_filters", False)) else 0.0),
                )
                if strategy_specific_block:
                    if (
                        action_symbol_key == "XAUUSD"
                        and is_grid_setup
                        and session_name in set(policy.xau_grid_allowed_sessions)
                        and bool(policy.xau_grid_allow_neutral_rsi)
                        and "neutral" in str(strategy_specific_block).lower()
                    ):
                        strategy_specific_block = None
                    elif (
                        action_symbol_key == "XAUUSD"
                        and is_grid_setup
                        and session_name in set(policy.xau_grid_allowed_sessions)
                        and bool(policy.xau_grid_new_cycle_soft_allow)
                        and "new_cycle" in str(strategy_specific_block).lower()
                    ):
                        strategy_specific_block = None
                    elif (is_canary_candidate or is_force_test_trade) and _proof_delivery_override_reason(str(strategy_specific_block)):
                        _log(
                            logger,
                            "info",
                            "CANARY_TRADE_OVERRIDE" if is_canary_candidate else "FORCE_TEST_TRADE_OVERRIDE",
                            symbol=action_symbol_key,
                            signal_id=str(row["signal_id"]),
                            stage="strategy_specific",
                            reason=str(strategy_specific_block),
                        )
                        strategy_specific_block = None
                if strategy_specific_block:
                    queue.update_scoring(
                        signal_id=str(row["signal_id"]),
                        confluence_score=confluence,
                        action_score=0.0,
                        risk_cost=risk_cost,
                        reason=f"blocked:{strategy_specific_block}",
                    )
                    updates = {"last_block_reason": str(strategy_specific_block)}
                    if isinstance(strategy_meta, dict) and strategy_meta.get("news_mode_state"):
                        updates["news_mode_state"] = str(strategy_meta["news_mode_state"])
                    queue.update_symbol_state(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        updates=updates,
                    )
                    queue.increment_block_reason(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        reason=str(strategy_specific_block),
                    )
                    _record_decision(
                        symbol_key=action_symbol_key,
                        signal_id=str(row["signal_id"]),
                        decision_type="entry_block",
                        reason=str(strategy_specific_block),
                        session_name=session_name,
                        strategy_key=strategy_key,
                        setup=setup_name,
                        probability=probability,
                        expected_value_r=net_expected_value_r,
                        confluence=confluence,
                        ai_mode=str(ai_runtime.get("last_ai_mode", "")),
                        extra={"starvation_mode": bool(governor_adjustments.get("active", False)), "reject_stage": "strategy_specific"},
                    )
                    _runtime_update(action_symbol_key, {"last_reject_stage": "strategy_specific", "last_reject_reason": str(strategy_specific_block)})
                    _record_reject_activity(action_symbol_key, str(strategy_specific_block), now_ts=now)
                    blocked_reasons.append(f"{row['signal_id']}:{strategy_specific_block}")
                    continue
                news_allowed, news_reason = _news_allowed(
                    news_status=str(row["news_status"] or ""),
                    probability=probability,
                    confluence=confluence,
                    spread_points=effective_spread_points,
                    rule=action_rule,
                    risk_cost=risk_cost,
                )
                if (
                    not news_allowed
                    and action_symbol_key == "USOIL"
                    and str(policy.news_mode).upper() == "ALLOW_HIGH_CONF"
                    and str(news_reason).startswith("news_armed_")
                ):
                    news_allowed = True
                    news_reason = "NEWS_ARMED_OIL_DEFER"
                    stricter_oil_floor = float(
                        (
                            (policy.oil_strategy.get("news_armed", {}) if isinstance(policy.oil_strategy, dict) else {})
                            or {}
                        ).get("stricter_confluence_floor", max(float(policy.min_confluence_score), 0.72))
                    )
                    confluence_floor = max(float(confluence_floor), stricter_oil_floor)
                    _runtime_update(
                        action_symbol_key,
                        {
                            "news_mode_state": news_reason,
                            "news_override_reason": "oil_news_armed_threshold_check",
                            "oil_news_armed_confluence_floor": float(confluence_floor),
                        },
                    )
                if not news_allowed and xau_high_conf_news_override:
                    news_allowed = True
                    news_reason = "NEWS_ARMED_XAU_DEFER"
                    _runtime_update(
                        action_symbol_key,
                        {
                            "news_mode_state": news_reason,
                            "news_override_reason": "xau_high_conf_news_gate_defer",
                        },
                    )
                effective_news_state = str(strategy_meta.get("news_mode_state", news_reason)) if isinstance(strategy_meta, dict) else str(news_reason)
                news_state_key = f"{account_id}:{int(magic)}:{action_symbol_key}"
                previous_news_state = news_mode_log_state.get(news_state_key, "")
                if previous_news_state != effective_news_state:
                    _log(
                        logger,
                        "info",
                        "news_mode_transition",
                        account=account_id,
                        magic=int(magic),
                        symbol=action_symbol_key,
                        previous=previous_news_state or "INIT",
                        current=effective_news_state,
                    )
                    news_mode_log_state[news_state_key] = effective_news_state
                nas_selective_spread_bypass = (
                    action_symbol_key == "NAS100"
                    and (
                        str(omega_label).upper() == "VOLATILE"
                        or str(row["regime"] or "").upper() == "VOLATILE"
                    )
                    and float(probability) >= 0.70
                    and float(confluence) >= 0.55
                    and float(net_expected_value_r) >= 0.25
                    and float(effective_spread_points) <= max(90.0, float(spread_limit_other) * 1.80)
                )
                row_payload = dict(row)
                bundle_pair_directives = dict(((learning_policy or {}).get("bundle") or {}).get("pair_directives") or {})
                active_pair_directive = dict(bundle_pair_directives.get(action_symbol_key) or {})
                strategy_block, state_updates = _strategy_state_block_reason(
                    account=account_id,
                    magic=int(magic),
                    symbol_key=action_symbol_key,
                    session_name=session_name,
                    timeframe_value=evaluation_timeframe,
                    setup=str(row["setup"] or ""),
                    side=side,
                    entry_price=entry_price,
                    equity=current_equity,
                    estimated_loss_usd=estimated_loss,
                    budget_usd=budget_usd,
                    spread_points=effective_spread_points,
                    stop_price=float(risk_stop_price),
                    point_size=float(action_rule.point),
                    spread_limit_grid=spread_limit_grid,
                    spread_limit_other=max(spread_limit_other, float(effective_spread_points)) if nas_selective_spread_bypass else spread_limit_other,
                    typical_spread_points=float(action_rule.typical_spread_points),
                    spread_reference_points=float(spread_reference_points),
                    spread_atr_points=float(spread_atr_points),
                    probability=float(probability),
                    expected_value_r=float(expected_value_r),
                    confluence=float(confluence),
                    current_time=now,
                    restrict_low_confidence=bool(policy.reality_restrict_new_exposure_on_low_confidence),
                    throughput_recovery_active=bool(
                        row_payload.get("throughput_recovery_active")
                        or (strategy_meta.get("throughput_recovery_active") if isinstance(strategy_meta, dict) else False)
                    ),
                    lane_strength_multiplier=float(
                        row_payload.get("lane_strength_multiplier")
                        or (strategy_meta.get("lane_strength_multiplier") if isinstance(strategy_meta, dict) else 1.0)
                        or 1.0
                    ),
                    session_density_score=float(
                        row_payload.get("session_density_score")
                        or (strategy_meta.get("session_density_score") if isinstance(strategy_meta, dict) else 0.0)
                        or 0.0
                    ),
                    strategy_recent_performance=float(
                        row_payload.get("strategy_recent_performance")
                        or (strategy_meta.get("strategy_recent_performance") if isinstance(strategy_meta, dict) else 0.0)
                        or 0.0
                    ),
                    hot_hand_active=bool(
                        row_payload.get("hot_hand_active")
                        or (strategy_meta.get("hot_hand_active") if isinstance(strategy_meta, dict) else False)
                    ),
                    pair_directive=active_pair_directive,
                    execution_quality_score=float(
                        row_payload.get("execution_quality_score")
                        or (strategy_meta.get("execution_quality_score") if isinstance(strategy_meta, dict) else 0.70)
                        or 0.70
                    ),
                    slippage_quality_score=float(
                        row_payload.get("slippage_quality_score")
                        or active_pair_directive.get("slippage_quality_score")
                        or (strategy_meta.get("slippage_quality_score") if isinstance(strategy_meta, dict) else 0.70)
                        or 0.70
                    ),
                    microstructure_alignment=float(
                        row_payload.get("microstructure_alignment_score")
                        or row_payload.get("microstructure_score")
                        or (strategy_meta.get("microstructure_alignment_score") if isinstance(strategy_meta, dict) else 0.50)
                        or 0.50
                    ),
                    adverse_entry_risk=float(
                        row_payload.get("adverse_entry_risk")
                        or (strategy_meta.get("adverse_entry_risk") if isinstance(strategy_meta, dict) else 0.25)
                        or 0.25
                    ),
                )
                strategy_state_value = str(
                    row_payload.get("strategy_state")
                    or (strategy_meta.get("strategy_state") if isinstance(strategy_meta, dict) else "")
                    or ""
                ).upper()
                if not strategy_block:
                    targeted_live_block, targeted_live_updates = _targeted_live_loss_bucket_block_reason(
                        symbol_key=action_symbol_key,
                        setup=str(row["setup"] or ""),
                        strategy_state=strategy_state_value,
                    )
                    if targeted_live_updates:
                        state_updates = {**dict(state_updates), **dict(targeted_live_updates)}
                    if targeted_live_block:
                        strategy_block = targeted_live_block
                if strategy_block:
                    if (is_canary_candidate or is_force_test_trade) and _proof_delivery_override_reason(str(strategy_block)):
                        _log(
                            logger,
                            "info",
                            "CANARY_TRADE_OVERRIDE" if is_canary_candidate else "FORCE_TEST_TRADE_OVERRIDE",
                            symbol=action_symbol_key,
                            signal_id=str(row["signal_id"]),
                            stage="strategy_state",
                            reason=str(strategy_block),
                        )
                        strategy_block = None
                    elif nas_selective_spread_bypass and str(strategy_block) == "spread_block_other":
                        state_updates = dict(state_updates)
                        state_updates["spread_override_reason"] = "nas_selective_volatile_bypass"
                        strategy_block = None
                if strategy_block:
                    state_updates["last_block_reason"] = strategy_block
                    queue.update_symbol_state(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        updates=state_updates,
                    )
                    queue.increment_block_reason(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        reason=str(strategy_block),
                    )
                    queue.update_scoring(
                        signal_id=str(row["signal_id"]),
                        confluence_score=confluence,
                        action_score=0.0,
                        risk_cost=0.0,
                        reason=f"blocked:{strategy_block}",
                    )
                    _record_decision(
                        symbol_key=action_symbol_key,
                        signal_id=str(row["signal_id"]),
                        decision_type="entry_block",
                        reason=str(strategy_block),
                        session_name=session_name,
                        strategy_key=strategy_key,
                        setup=setup_name,
                        probability=probability,
                        expected_value_r=expected_value_r,
                        confluence=confluence,
                        ai_mode=str(ai_runtime.get("last_ai_mode", "")),
                        extra={"starvation_mode": bool(governor_adjustments.get("active", False)), "reject_stage": "strategy_state"},
                    )
                    _runtime_update(action_symbol_key, {"last_reject_stage": "strategy_state", "last_reject_reason": str(strategy_block)})
                    _record_reject_activity(action_symbol_key, str(strategy_block), now_ts=now)
                    blocked_reasons.append(f"{row['signal_id']}:{strategy_block}")
                    continue
                if state_updates:
                    queue.update_symbol_state(
                        account=account_id,
                        magic=int(magic),
                        symbol_key=action_symbol_key,
                        timeframe=evaluation_timeframe,
                        updates=state_updates,
                    )
                    row_context.update(state_updates)
                risk_margin_free = _safe_float(account_snapshot.get("free_margin"), 0.0)
                if free_margin is not None:
                    risk_margin_free = _safe_float(free_margin, risk_margin_free)
                risk_margin_per_lot = _estimated_margin_per_lot(
                    symbol_key=action_symbol_key,
                    entry_price=float(entry_price),
                    contract_size=float(action_rule.contract_size),
                    leverage=_safe_float(account_snapshot.get("leverage"), 0.0),
                ) or 0.0
                risk_reason, risk_gate_details = _risk_block_reason(
                    action_type=action_type,
                    symbol_key=action_symbol_key,
                    account=account_id,
                    magic=int(magic),
                    session_name=session_name,
                    setup_name=setup_name,
                    news_allowed=news_allowed,
                    news_state=effective_news_state,
                    news_confidence=_safe_float(row_context.get("news_confidence"), 0.70),
                    market_open=_market_open_status(action_symbol_key, now)[0],
                    equity=current_equity,
                    probability=probability,
                    expected_value_r=expected_value_r,
                    confluence=confluence,
                    estimated_loss_usd=estimated_loss,
                    budget_usd=budget_usd,
                    lot=float(row["lot"] or 0.0),
                    stop_distance=abs(float(entry_price) - float(risk_stop_price)),
                    min_lot=float(_effective_min_lot(action_symbol_key, account_snapshot)),
                    contract_size=float(action_rule.contract_size),
                    tick_size=float(action_rule.tick_size),
                    tick_value=float(action_rule.tick_value),
                    free_margin=float(risk_margin_free) if risk_margin_free > 0 else None,
                    margin_per_lot=float(risk_margin_per_lot) if risk_margin_per_lot > 0 else None,
                    confluence_floor=max(0.30, confluence_floor),
                    min_probability_floor=min_probability_floor,
                    min_ev_floor=min_ev_floor,
                    account_snapshot=account_snapshot,
                    context={
                        **row_context,
                        "current_phase": symbol_runtime_state.get(action_symbol_key, {}).get("current_phase", row_context.get("current_phase", "PHASE_1")),
                        "current_risk_pct": symbol_runtime_state.get(action_symbol_key, {}).get("current_risk_pct", row_context.get("current_risk_pct", 0.03)),
                        "current_max_risk_pct": symbol_runtime_state.get(action_symbol_key, {}).get("current_max_risk_pct", row_context.get("current_max_risk_pct", 0.05)),
                        "current_ai_threshold_mode": symbol_runtime_state.get(action_symbol_key, {}).get("current_ai_threshold_mode", row_context.get("current_ai_threshold_mode", "conservative")),
                        "session_quality_score": row_context.get("session_quality_score", 0.75),
                        "spread_quality_score": row_context.get("spread_quality_score", 0.75),
                        "xau_grid_cycle_quality": row_context.get("xau_grid_cycle_quality", row_context.get("trade_quality_score", 0.0)),
                    },
                )
                if action_symbol_key == "XAUUSD" and is_grid_setup:
                    risk_runtime = {
                        "micro_account_mode": bool(risk_gate_details.get("micro_account_mode")),
                        "pre_exec_pass": risk_gate_details.get("pre_exec_pass"),
                        "pre_exec_fail_reason": str(risk_gate_details.get("pre_exec_fail_reason") or ""),
                        "min_lot_loss_usd": float(risk_gate_details.get("min_lot_loss_usd", 0.0) or 0.0),
                        "risk_cap_usd": float(risk_gate_details.get("risk_cap_usd", 0.0) or 0.0),
                        "chosen_stop_distance": float(risk_gate_details.get("chosen_stop_distance", 0.0) or 0.0),
                        "chosen_spacing_points": float(ai_summary.get("chosen_spacing_points") or 0.0),
                        "last_grid_block_reason": str(risk_reason or ""),
                        "session_allowed": bool(session_name in set(policy.xau_grid_allowed_sessions)),
                    }
                    _runtime_update(action_symbol_key, risk_runtime)
                spread_ref = float(spread_limit_grid if _is_grid_setup(str(row["setup"] or "")) else spread_limit_other)
                btc_delivery_spread_fraction = None
                if action_symbol_key == "BTCUSD":
                    btc_delivery_spread_fraction = _spread_price_fraction(
                        spread_points=effective_spread_points,
                        point_size=float(action_rule.point),
                        reference_price=entry_price if entry_price > 0 else float(row["entry_price"] or 0.0),
                    )
                    if btc_delivery_spread_fraction <= 0.00035:
                        spread_ref = max(
                            spread_ref,
                            max(float(action_rule.typical_spread_points), 1.0) * 20.0,
                            effective_spread_points * 1.05,
                        )
                        _runtime_update(
                            action_symbol_key,
                            {
                                "btc_delivery_spread_fraction": btc_delivery_spread_fraction,
                                "btc_delivery_spread_cap_points": float(spread_ref),
                            },
                        )
                spread_penalty = clamp(effective_spread_points / max(spread_ref, 1.0), 0.0, 1.0)
                if is_force_test_trade:
                    spread_ref = max(float(spread_ref), float(effective_spread_points) * 1.10)
                if risk_reason is not None:
                    if (is_canary_candidate or is_force_test_trade) and _proof_delivery_override_reason(str(risk_reason)):
                        _log(
                            logger,
                            "info",
                            "CANARY_TRADE_OVERRIDE" if is_canary_candidate else "FORCE_TEST_TRADE_OVERRIDE",
                            symbol=action_symbol_key,
                            signal_id=str(row["signal_id"]),
                            stage="pre_exec_quality",
                            reason=str(risk_reason),
                        )
                        risk_reason = None
                if risk_reason is not None:
                    aggressive_micro_relief = (
                        str(risk_reason) == "candidate_rejected_pre_exec:min_lot_over_budget"
                        and float(current_equity) <= max(250.0, float(policy.bootstrap_equity_threshold))
                        and (
                            bool(governor_adjustments.get("disable_low_weight_filters", False))
                            or float(governor_adjustments.get("performance_loosen_pct", 0.0)) > 0.0
                            or float(probability) >= 0.80
                            or float(expected_value_r) >= 0.50
                            or float(confluence) >= 0.70
                        )
                    )
                    if aggressive_micro_relief:
                        risk_gate_details["pre_exec_pass"] = True
                        risk_gate_details["pre_exec_fail_reason"] = ""
                        risk_gate_details["pre_exec_override_reason"] = "aggressive_micro_lot_relief"
